INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-budgeting-b-1','finance','finance:budgeting','finance-budgeting-b-1','beginner','mcq','What is the main purpose of a personal budget?','What is the main purpose of a personal budget?',ARRAY['To plan how income is allocated across spending and saving','To guarantee a higher salary each year','To eliminate the need to ever track expenses','To replace the need for a bank account']::text[],ARRAY['To plan how income is allocated across spending and saving','To guarantee a higher salary each year','To eliminate the need to ever track expenses','To replace the need for a bank account']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A budget is a plan that allocates your income across expenses, savings, and goals.','A budget is a plan that allocates your income across expenses, savings, and goals.','A budget is a forward-looking plan for your money. It assigns every dollar of income to a purpose, such as bills, spending, or saving. Reviewing it regularly helps you spot overspending and stay on track toward goals.','A budget is a forward-looking plan for your money. It assigns every dollar of income to a purpose, such as bills, spending, or saving. Reviewing it regularly helps you spot overspending and stay on track toward goals.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-budgeting-b-2','finance','finance:budgeting','finance-budgeting-b-2','beginner','truefalse','An emergency fund is money set aside to cover unexpected expenses such as car repairs or medical bills.','An emergency fund is money set aside to cover unexpected expenses such as car repairs or medical bills.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'An emergency fund is savings reserved specifically for unexpected, urgent costs.','An emergency fund is savings reserved specifically for unexpected, urgent costs.','An emergency fund is a cash reserve held in an easily accessible account. It cushions against surprises like job loss or sudden repairs so you avoid borrowing at high interest. A common guideline is to save three to six months of essential expenses.','An emergency fund is a cash reserve held in an easily accessible account. It cushions against surprises like job loss or sudden repairs so you avoid borrowing at high interest. A common guideline is to save three to six months of essential expenses.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-budgeting-i-1','finance','finance:budgeting','finance-budgeting-i-1','intermediate','mcq','In the popular 50/30/20 budgeting guideline, what does the 20% portion represent?','In the popular 50/30/20 budgeting guideline, what does the 20% portion represent?',ARRAY['Savings and debt repayment','Housing costs only','Entertainment and dining out','Taxes withheld from your paycheck']::text[],ARRAY['Savings and debt repayment','Housing costs only','Entertainment and dining out','Taxes withheld from your paycheck']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'In the 50/30/20 guideline, 20% of after-tax income goes to savings and paying down debt.','In the 50/30/20 guideline, 20% of after-tax income goes to savings and paying down debt.','The 50/30/20 rule splits after-tax income into three buckets. Fifty percent covers needs, thirty percent covers wants, and twenty percent goes to savings and extra debt repayment. It is a flexible starting framework, not a rigid rule.','The 50/30/20 rule splits after-tax income into three buckets. Fifty percent covers needs, thirty percent covers wants, and twenty percent goes to savings and extra debt repayment. It is a flexible starting framework, not a rigid rule.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-budgeting-i-2','finance','finance:budgeting','finance-budgeting-i-2','intermediate','mcq','Why is paying yourself first considered an effective saving strategy?','Why is paying yourself first considered an effective saving strategy?',ARRAY['Saving happens automatically before money can be spent','It increases your gross salary','It removes the need for any budget','It guarantees investment returns']::text[],ARRAY['Saving happens automatically before money can be spent','It increases your gross salary','It removes the need for any budget','It guarantees investment returns']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Paying yourself first moves savings out automatically before discretionary spending can consume it.','Paying yourself first moves savings out automatically before discretionary spending can consume it.','Paying yourself first means directing a set amount to savings as soon as you are paid, often through automation. Because the money leaves before you can spend it, saving becomes consistent and effortless. This habit treats savings as a fixed priority rather than leftover money.','Paying yourself first means directing a set amount to savings as soon as you are paid, often through automation. Because the money leaves before you can spend it, saving becomes consistent and effortless. This habit treats savings as a fixed priority rather than leftover money.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-budgeting-a-1','finance','finance:budgeting','finance-budgeting-a-1','advanced','mcq','What distinguishes a zero-based budget from other budgeting methods?','What distinguishes a zero-based budget from other budgeting methods?',ARRAY['Every dollar of income is assigned a specific job until nothing is left unallocated','You must spend down your account to zero each month','It only works for people with no debt','It ignores irregular or variable expenses']::text[],ARRAY['Every dollar of income is assigned a specific job until nothing is left unallocated','You must spend down your account to zero each month','It only works for people with no debt','It ignores irregular or variable expenses']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'In a zero-based budget, income minus all allocations equals zero, so every dollar has an assigned purpose.','In a zero-based budget, income minus all allocations equals zero, so every dollar has an assigned purpose.','Zero-based budgeting gives every dollar a job, including savings and debt payments, until allocations equal income. It does not mean your bank balance hits zero. The method forces deliberate decisions about all income, which improves awareness and reduces aimless spending.','Zero-based budgeting gives every dollar a job, including savings and debt payments, until allocations equal income. It does not mean your bank balance hits zero. The method forces deliberate decisions about all income, which improves awareness and reduces aimless spending.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-budgeting-a-2','finance','finance:budgeting','finance-budgeting-a-2','advanced','mcq','When building a budget around an irregular income, which approach is generally most stable?','When building a budget around an irregular income, which approach is generally most stable?',ARRAY['Base spending on a conservative estimate of your lowest typical monthly income','Base spending on your single highest-earning month','Spend each month''s full income immediately','Avoid saving until income becomes predictable']::text[],ARRAY['Base spending on a conservative estimate of your lowest typical monthly income','Base spending on your single highest-earning month','Spend each month''s full income immediately','Avoid saving until income becomes predictable']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Budgeting from a conservative low-income baseline prevents overcommitting during lean months.','Budgeting from a conservative low-income baseline prevents overcommitting during lean months.','Variable income makes fixed commitments risky if based on good months. Budgeting from a conservative baseline of your lowest typical earnings keeps essential spending sustainable. Surplus from stronger months can then build a buffer that smooths out the lean periods.','Variable income makes fixed commitments risky if based on good months. Budgeting from a conservative baseline of your lowest typical earnings keeps essential spending sustainable. Surplus from stronger months can then build a buffer that smooths out the lean periods.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-credit-b-1','finance','finance:credit','finance-credit-b-1','beginner','mcq','What does a credit score primarily measure?','What does a credit score primarily measure?',ARRAY['How likely you are to repay borrowed money','How much money you currently have in savings','Your total annual income','The value of your home']::text[],ARRAY['How likely you are to repay borrowed money','How much money you currently have in savings','Your total annual income','The value of your home']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A credit score estimates your creditworthiness, or how likely you are to repay debt.','A credit score estimates your creditworthiness, or how likely you are to repay debt.','A credit score is a number summarizing your credit history. Lenders use it to gauge the risk of lending to you, which affects approval and interest rates. It reflects borrowing behavior, not your income or wealth.','A credit score is a number summarizing your credit history. Lenders use it to gauge the risk of lending to you, which affects approval and interest rates. It reflects borrowing behavior, not your income or wealth.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-credit-b-2','finance','finance:credit','finance-credit-b-2','beginner','truefalse','Paying your credit card bill in full each month lets you avoid interest charges on purchases.','Paying your credit card bill in full each month lets you avoid interest charges on purchases.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Paying the full statement balance by the due date avoids interest on regular purchases during the grace period.','Paying the full statement balance by the due date avoids interest on regular purchases during the grace period.','Credit cards typically offer a grace period on purchases when you pay the statement balance in full by the due date. Carrying a balance forfeits that grace period and triggers interest charges. Paying in full each month is the cheapest way to use a credit card.','Credit cards typically offer a grace period on purchases when you pay the statement balance in full by the due date. Carrying a balance forfeits that grace period and triggers interest charges. Paying in full each month is the cheapest way to use a credit card.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-credit-i-1','finance','finance:credit','finance-credit-i-1','intermediate','mcq','Credit utilization, an important scoring factor, refers to what?','Credit utilization, an important scoring factor, refers to what?',ARRAY['The share of your available revolving credit that you are currently using','The number of years your oldest account has been open','How many times you check your own credit report','The total amount you have ever borrowed in your life']::text[],ARRAY['The share of your available revolving credit that you are currently using','The number of years your oldest account has been open','How many times you check your own credit report','The total amount you have ever borrowed in your life']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Credit utilization is the ratio of your balances to your available credit limits.','Credit utilization is the ratio of your balances to your available credit limits.','Credit utilization compares how much revolving credit you are using to your total available limits. Lower utilization generally signals less risk and supports a higher score. Keeping balances well below your limits is widely recommended.','Credit utilization compares how much revolving credit you are using to your total available limits. Lower utilization generally signals less risk and supports a higher score. Keeping balances well below your limits is widely recommended.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-credit-i-2','finance','finance:credit','finance-credit-i-2','intermediate','mcq','Which factor typically has the largest influence on a common credit score?','Which factor typically has the largest influence on a common credit score?',ARRAY['Your payment history','Your employer''s name','Your account passwords','The brand of card you carry']::text[],ARRAY['Your payment history','Your employer''s name','Your account passwords','The brand of card you carry']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Payment history, whether you pay on time, is usually the most heavily weighted scoring factor.','Payment history, whether you pay on time, is usually the most heavily weighted scoring factor.','Most scoring models weight payment history most heavily because on-time payment is the strongest signal of reliability. Even one late payment can hurt a score and linger on a report for years. Consistently paying on time is the single best way to build credit.','Most scoring models weight payment history most heavily because on-time payment is the strongest signal of reliability. Even one late payment can hurt a score and linger on a report for years. Consistently paying on time is the single best way to build credit.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-credit-a-1','finance','finance:credit','finance-credit-a-1','advanced','mcq','With the debt avalanche repayment method, which debt do you target first?','With the debt avalanche repayment method, which debt do you target first?',ARRAY['The debt with the highest interest rate','The debt with the smallest balance','The newest debt you took on','The debt with the longest term']::text[],ARRAY['The debt with the highest interest rate','The debt with the smallest balance','The newest debt you took on','The debt with the longest term']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The avalanche method prioritizes the highest-interest debt to minimize total interest paid.','The avalanche method prioritizes the highest-interest debt to minimize total interest paid.','The debt avalanche attacks the highest interest rate first while paying minimums on the rest. Mathematically it minimizes total interest and time to payoff. It contrasts with the snowball method, which targets the smallest balance first for motivational quick wins.','The debt avalanche attacks the highest interest rate first while paying minimums on the rest. Mathematically it minimizes total interest and time to payoff. It contrasts with the snowball method, which targets the smallest balance first for motivational quick wins.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-credit-a-2','finance','finance:credit','finance-credit-a-2','advanced','mcq','Why can closing an old, unused credit card sometimes lower your credit score?','Why can closing an old, unused credit card sometimes lower your credit score?',ARRAY['It can reduce total available credit and shorten average account age','It immediately erases your entire credit history','It always converts the account into a loan','It raises your income on file']::text[],ARRAY['It can reduce total available credit and shorten average account age','It immediately erases your entire credit history','It always converts the account into a loan','It raises your income on file']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Closing a card removes its limit and can raise utilization while reducing average account age.','Closing a card removes its limit and can raise utilization while reducing average account age.','Closing a card eliminates its credit limit, which can push your utilization ratio higher across remaining cards. It may also lower the average age of your accounts over time. Both effects can modestly reduce a score, so keeping old cards open is often wise.','Closing a card eliminates its credit limit, which can push your utilization ratio higher across remaining cards. It may also lower the average age of your accounts over time. Both effects can modestly reduce a score, so keeping old cards open is often wise.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-investing-b-1','finance','finance:investing','finance-investing-b-1','beginner','mcq','What does diversification mean in investing?','What does diversification mean in investing?',ARRAY['Spreading money across many investments to reduce risk','Putting all your money in one promising stock','Avoiding the stock market entirely','Trading as frequently as possible']::text[],ARRAY['Spreading money across many investments to reduce risk','Putting all your money in one promising stock','Avoiding the stock market entirely','Trading as frequently as possible']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Diversification spreads investments across assets so no single loss is devastating.','Diversification spreads investments across assets so no single loss is devastating.','Diversification means holding a mix of investments rather than concentrating in one. Because different assets often move differently, losses in one may be offset by gains in another. This reduces the impact of any single investment performing poorly.','Diversification means holding a mix of investments rather than concentrating in one. Because different assets often move differently, losses in one may be offset by gains in another. This reduces the impact of any single investment performing poorly.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-investing-b-2','finance','finance:investing','finance-investing-b-2','beginner','truefalse','In general, investments offering higher potential returns also tend to carry higher risk.','In general, investments offering higher potential returns also tend to carry higher risk.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The risk-return tradeoff means higher expected returns generally come with greater risk.','The risk-return tradeoff means higher expected returns generally come with greater risk.','The risk-return tradeoff is a core investing principle. Assets with higher potential reward, like stocks, typically come with greater volatility and chance of loss. Lower-risk assets, like cash, usually offer smaller returns.','The risk-return tradeoff is a core investing principle. Assets with higher potential reward, like stocks, typically come with greater volatility and chance of loss. Lower-risk assets, like cash, usually offer smaller returns.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-investing-i-1','finance','finance:investing','finance-investing-i-1','intermediate','mcq','What is a key advantage of a low-cost index fund?','What is a key advantage of a low-cost index fund?',ARRAY['It offers broad market exposure with low fees','It guarantees you will beat the market every year','It eliminates all investment risk','It requires picking individual winning stocks']::text[],ARRAY['It offers broad market exposure with low fees','It guarantees you will beat the market every year','It eliminates all investment risk','It requires picking individual winning stocks']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Index funds track a broad market index cheaply, giving wide diversification at low cost.','Index funds track a broad market index cheaply, giving wide diversification at low cost.','An index fund passively tracks a market index rather than trying to beat it. This keeps fees low and provides instant diversification across many holdings. Lower costs and broad exposure are why index funds are a common core holding.','An index fund passively tracks a market index rather than trying to beat it. This keeps fees low and provides instant diversification across many holdings. Lower costs and broad exposure are why index funds are a common core holding.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-investing-i-2','finance','finance:investing','finance-investing-i-2','intermediate','mcq','What does dollar-cost averaging involve?','What does dollar-cost averaging involve?',ARRAY['Investing a fixed amount at regular intervals regardless of price','Investing only when prices reach a yearly low','Selling everything whenever the market drops','Putting your entire savings in at one moment']::text[],ARRAY['Investing a fixed amount at regular intervals regardless of price','Investing only when prices reach a yearly low','Selling everything whenever the market drops','Putting your entire savings in at one moment']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Dollar-cost averaging invests a set amount on a regular schedule, smoothing out price swings.','Dollar-cost averaging invests a set amount on a regular schedule, smoothing out price swings.','Dollar-cost averaging means investing a fixed sum at regular intervals no matter the price. You buy more shares when prices are low and fewer when high, averaging your cost over time. It reduces the pressure to time the market and encourages consistent investing.','Dollar-cost averaging means investing a fixed sum at regular intervals no matter the price. You buy more shares when prices are low and fewer when high, averaging your cost over time. It reduces the pressure to time the market and encourages consistent investing.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-investing-a-1','finance','finance:investing','finance-investing-a-1','advanced','mcq','How does compound interest differ from simple interest over the long term?','How does compound interest differ from simple interest over the long term?',ARRAY['Compound interest earns returns on both the principal and previously earned interest','Compound interest only ever applies to loans, never savings','Compound interest always produces lower totals than simple interest','Compound interest ignores the principal entirely']::text[],ARRAY['Compound interest earns returns on both the principal and previously earned interest','Compound interest only ever applies to loans, never savings','Compound interest always produces lower totals than simple interest','Compound interest ignores the principal entirely']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Compounding earns returns on accumulated interest as well as principal, accelerating growth over time.','Compounding earns returns on accumulated interest as well as principal, accelerating growth over time.','Simple interest is calculated only on the original principal. Compound interest is calculated on the principal plus all previously accumulated interest. Over long periods this compounding effect causes balances to grow far faster, which is why starting early matters so much.','Simple interest is calculated only on the original principal. Compound interest is calculated on the principal plus all previously accumulated interest. Over long periods this compounding effect causes balances to grow far faster, which is why starting early matters so much.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-investing-a-2','finance','finance:investing','finance-investing-a-2','advanced','mcq','What is the main purpose of periodically rebalancing a portfolio?','What is the main purpose of periodically rebalancing a portfolio?',ARRAY['To restore the target mix of assets after market moves shift the weights','To sell all investments and hold only cash','To chase whichever asset rose the most recently','To avoid ever paying any taxes']::text[],ARRAY['To restore the target mix of assets after market moves shift the weights','To sell all investments and hold only cash','To chase whichever asset rose the most recently','To avoid ever paying any taxes']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Rebalancing realigns holdings to your intended allocation after returns drift the weights apart.','Rebalancing realigns holdings to your intended allocation after returns drift the weights apart.','Over time, stronger-performing assets grow to occupy a larger share of a portfolio, shifting its risk level. Rebalancing sells some of what has grown and buys what has lagged to restore target weights. This keeps risk aligned with your plan and enforces a disciplined buy-low, sell-high habit.','Over time, stronger-performing assets grow to occupy a larger share of a portfolio, shifting its risk level. Rebalancing sells some of what has grown and buys what has lagged to restore target weights. This keeps risk aligned with your plan and enforces a disciplined buy-low, sell-high habit.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-retirement-b-1','finance','finance:retirement','finance-retirement-b-1','beginner','mcq','What is a primary purpose of a retirement account?','What is a primary purpose of a retirement account?',ARRAY['To save and invest money for income later in life, often with tax advantages','To provide unlimited free withdrawals at any age','To replace the need for any other savings','To avoid earning any investment returns']::text[],ARRAY['To save and invest money for income later in life, often with tax advantages','To provide unlimited free withdrawals at any age','To replace the need for any other savings','To avoid earning any investment returns']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Retirement accounts help you save and invest for later life, usually with tax benefits.','Retirement accounts help you save and invest for later life, usually with tax benefits.','Retirement accounts are designed to help you accumulate money for your non-working years. Many offer tax advantages to encourage long-term saving. In exchange, they often restrict withdrawals until you reach a certain age.','Retirement accounts are designed to help you accumulate money for your non-working years. Many offer tax advantages to encourage long-term saving. In exchange, they often restrict withdrawals until you reach a certain age.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-retirement-b-2','finance','finance:retirement','finance-retirement-b-2','beginner','truefalse','If an employer matches contributions to your retirement plan, contributing at least enough to get the full match is generally a good idea.','If an employer matches contributions to your retirement plan, contributing at least enough to get the full match is generally a good idea.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'An employer match is essentially free money, so capturing the full match is widely recommended.','An employer match is essentially free money, so capturing the full match is widely recommended.','Many employers match a portion of what you contribute to a workplace retirement plan. That match is additional compensation you only receive if you contribute. Contributing enough to earn the full match is one of the most reliable ways to boost retirement savings.','Many employers match a portion of what you contribute to a workplace retirement plan. That match is additional compensation you only receive if you contribute. Contributing enough to earn the full match is one of the most reliable ways to boost retirement savings.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-retirement-i-1','finance','finance:retirement','finance-retirement-i-1','intermediate','mcq','What is the main difference between a traditional and a Roth retirement account regarding taxes?','What is the main difference between a traditional and a Roth retirement account regarding taxes?',ARRAY['Traditional contributions are typically pre-tax while Roth withdrawals are typically tax-free','Both are taxed identically in every situation','Roth accounts can never be invested in stocks','Traditional accounts are always tax-free at every stage']::text[],ARRAY['Traditional contributions are typically pre-tax while Roth withdrawals are typically tax-free','Both are taxed identically in every situation','Roth accounts can never be invested in stocks','Traditional accounts are always tax-free at every stage']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Traditional accounts generally defer taxes until withdrawal, while Roth accounts are funded after tax and grow tax-free.','Traditional accounts generally defer taxes until withdrawal, while Roth accounts are funded after tax and grow tax-free.','A traditional account often gives a tax break when you contribute, with taxes due on withdrawals in retirement. A Roth account uses after-tax money now, but qualified withdrawals later are tax-free. The choice often hinges on whether you expect a higher tax rate now or in retirement.','A traditional account often gives a tax break when you contribute, with taxes due on withdrawals in retirement. A Roth account uses after-tax money now, but qualified withdrawals later are tax-free. The choice often hinges on whether you expect a higher tax rate now or in retirement.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-retirement-i-2','finance','finance:retirement','finance-retirement-i-2','intermediate','mcq','What is the difference between a tax deduction and a tax credit?','What is the difference between a tax deduction and a tax credit?',ARRAY['A deduction lowers taxable income while a credit directly reduces the tax owed','They are two names for exactly the same thing','A credit increases your taxable income','A deduction always saves more than a credit of equal size']::text[],ARRAY['A deduction lowers taxable income while a credit directly reduces the tax owed','They are two names for exactly the same thing','A credit increases your taxable income','A deduction always saves more than a credit of equal size']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Deductions reduce the income that is taxed, while credits subtract directly from the tax bill.','Deductions reduce the income that is taxed, while credits subtract directly from the tax bill.','A tax deduction reduces the amount of income subject to tax, so its value depends on your tax rate. A tax credit reduces the actual tax you owe dollar for dollar. Because of this, a credit of a given size usually saves more than a deduction of the same size.','A tax deduction reduces the amount of income subject to tax, so its value depends on your tax rate. A tax credit reduces the actual tax you owe dollar for dollar. Because of this, a credit of a given size usually saves more than a deduction of the same size.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-retirement-a-1','finance','finance:retirement','finance-retirement-a-1','advanced','mcq','Why does starting retirement contributions earlier in life have an outsized effect on the final balance?','Why does starting retirement contributions earlier in life have an outsized effect on the final balance?',ARRAY['Earlier contributions have more time to compound, multiplying their growth','Early contributions are taxed at a lower rate by law','Money invested early is exempt from all market risk','Starting early reduces the total amount you must ever contribute to zero']::text[],ARRAY['Earlier contributions have more time to compound, multiplying their growth','Early contributions are taxed at a lower rate by law','Money invested early is exempt from all market risk','Starting early reduces the total amount you must ever contribute to zero']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'More years of compounding mean early contributions grow far larger than identical later ones.','More years of compounding mean early contributions grow far larger than identical later ones.','Time is the most powerful lever in retirement saving because of compounding. A dollar invested in your twenties has decades to earn returns on returns, while the same dollar invested later has less time to grow. This is why even small early contributions can outweigh larger ones made later.','Time is the most powerful lever in retirement saving because of compounding. A dollar invested in your twenties has decades to earn returns on returns, while the same dollar invested later has less time to grow. This is why even small early contributions can outweigh larger ones made later.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-finance-retirement-a-2','finance','finance:retirement','finance-retirement-a-2','advanced','mcq','What does the concept of asset location (as opposed to allocation) refer to?','What does the concept of asset location (as opposed to allocation) refer to?',ARRAY['Choosing which type of account holds each investment to improve tax efficiency','Deciding the overall percentage split between stocks and bonds','Picking which country to retire in','Storing physical share certificates in a safe place']::text[],ARRAY['Choosing which type of account holds each investment to improve tax efficiency','Deciding the overall percentage split between stocks and bonds','Picking which country to retire in','Storing physical share certificates in a safe place']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Asset location places investments in taxable or tax-advantaged accounts to minimize taxes.','Asset location places investments in taxable or tax-advantaged accounts to minimize taxes.','Asset allocation decides your overall mix of investments, while asset location decides which account type holds each one. Placing tax-inefficient assets in tax-advantaged accounts and tax-efficient ones in taxable accounts can reduce the taxes you pay. Thoughtful location can improve after-tax returns without changing your overall allocation.','Asset allocation decides your overall mix of investments, while asset location decides which account type holds each one. Placing tax-inefficient assets in tax-advantaged accounts and tax-efficient ones in taxable accounts can reduce the taxes you pay. Thoughtful location can improve after-tax returns without changing your overall allocation.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-averages-b-1','data','data:averages','data-averages-b-1','beginner','mcq','What is the mean (average) of the numbers 4, 8, and 9?','What is the mean (average) of the numbers 4, 8, and 9?',ARRAY['7','8','21','6']::text[],ARRAY['7','8','21','6']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Add the values to get 21, then divide by 3 to get 7.','Add the values to get 21, then divide by 3 to get 7.','The mean is found by adding all the values together and dividing by how many values there are. It is the most common type of average. It can be pulled toward unusually large or small values.','The mean is found by adding all the values together and dividing by how many values there are. It is the most common type of average. It can be pulled toward unusually large or small values.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-averages-b-2','data','data:averages','data-averages-b-2','beginner','mcq','What is the median of the sorted list 2, 5, 7, 10, 14?','What is the median of the sorted list 2, 5, 7, 10, 14?',ARRAY['7','5','10','8']::text[],ARRAY['7','5','10','8']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'With five values, the median is the middle (third) value, which is 7.','With five values, the median is the middle (third) value, which is 7.','The median is the middle value when the data is sorted in order. For an odd count it is the single central value; for an even count it is the average of the two central values. It is less affected by extreme values than the mean.','The median is the middle value when the data is sorted in order. For an odd count it is the single central value; for an even count it is the average of the two central values. It is less affected by extreme values than the mean.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-averages-i-1','data','data:averages','data-averages-i-1','intermediate','mcq','A dataset is 3, 3, 4, 5, 100. Which measure best describes a typical value, given the outlier?','A dataset is 3, 3, 4, 5, 100. Which measure best describes a typical value, given the outlier?',ARRAY['The median (4)','The mean (23)','The range (97)','The maximum (100)']::text[],ARRAY['The median (4)','The mean (23)','The range (97)','The maximum (100)']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The mean of 23 is distorted by the outlier 100, while the median of 4 reflects a typical value.','The mean of 23 is distorted by the outlier 100, while the median of 4 reflects a typical value.','Outliers are values far from the rest of the data. The mean is sensitive to outliers because every value affects the sum, but the median is resistant because it depends only on position. When data is skewed or has outliers, the median often describes a typical value better.','Outliers are values far from the rest of the data. The mean is sensitive to outliers because every value affects the sum, but the median is resistant because it depends only on position. When data is skewed or has outliers, the median often describes a typical value better.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-averages-i-2','data','data:averages','data-averages-i-2','intermediate','mcq','What is the mode of the dataset 6, 2, 6, 9, 2, 6?','What is the mode of the dataset 6, 2, 6, 9, 2, 6?',ARRAY['6','2','9','There is no mode']::text[],ARRAY['6','2','9','There is no mode']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The value 6 appears three times, more often than any other value.','The value 6 appears three times, more often than any other value.','The mode is the value that occurs most frequently in a dataset. A dataset can have one mode, more than one mode, or no mode if all values appear equally often. The mode is the only average that can be used with non-numeric categories.','The mode is the value that occurs most frequently in a dataset. A dataset can have one mode, more than one mode, or no mode if all values appear equally often. The mode is the only average that can be used with non-numeric categories.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-averages-a-1','data','data:averages','data-averages-a-1','advanced','mcq','Two classes both have a mean test score of 70. Class A scores cluster between 65 and 75; Class B has many scores near 40 and near 100. Which statement is correct?','Two classes both have a mean test score of 70. Class A scores cluster between 65 and 75; Class B has many scores near 40 and near 100. Which statement is correct?',ARRAY['Class B has a larger standard deviation than Class A','Class A has a larger standard deviation than Class B','Both classes have the same standard deviation','Standard deviation cannot differ when means are equal']::text[],ARRAY['Class B has a larger standard deviation than Class A','Class A has a larger standard deviation than Class B','Both classes have the same standard deviation','Standard deviation cannot differ when means are equal']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Class B''s scores are spread far from the mean, giving it a larger standard deviation despite the equal means.','Class B''s scores are spread far from the mean, giving it a larger standard deviation despite the equal means.','Standard deviation measures how spread out values are around the mean. A small standard deviation means values cluster tightly near the mean; a large one means they are widely scattered. Two datasets can share a mean yet have very different spreads.','Standard deviation measures how spread out values are around the mean. A small standard deviation means values cluster tightly near the mean; a large one means they are widely scattered. Two datasets can share a mean yet have very different spreads.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-averages-a-2','data','data:averages','data-averages-a-2','advanced','truefalse','True or false: Adding a value equal to the current mean to a dataset leaves the mean unchanged.','True or false: Adding a value equal to the current mean to a dataset leaves the mean unchanged.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Adding a value equal to the mean increases the sum and count proportionally, so the mean stays the same.','Adding a value equal to the mean increases the sum and count proportionally, so the mean stays the same.','The mean balances the data so that deviations above and below it cancel out. Adding a new value equal to the mean contributes zero net deviation, leaving the balance point fixed. Adding a value above or below the mean would shift the mean in that direction.','The mean balances the data so that deviations above and below it cancel out. Adding a new value equal to the mean contributes zero net deviation, leaving the balance point fixed. Adding a value above or below the mean would shift the mean in that direction.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-probability-b-1','data','data:probability','data-probability-b-1','beginner','mcq','What is the probability of rolling a 3 on a fair six-sided die?','What is the probability of rolling a 3 on a fair six-sided die?',ARRAY['1/6','1/3','3/6','1/2']::text[],ARRAY['1/6','1/3','3/6','1/2']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'There is one favorable outcome (a 3) out of six equally likely outcomes, giving 1/6.','There is one favorable outcome (a 3) out of six equally likely outcomes, giving 1/6.','Probability is the number of favorable outcomes divided by the total number of equally likely outcomes. It ranges from 0 (impossible) to 1 (certain). For a fair die, each of the six faces is equally likely.','Probability is the number of favorable outcomes divided by the total number of equally likely outcomes. It ranges from 0 (impossible) to 1 (certain). For a fair die, each of the six faces is equally likely.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-probability-b-2','data','data:probability','data-probability-b-2','beginner','mcq','A bag has 3 red and 7 blue marbles. What is the probability of drawing a red marble at random?','A bag has 3 red and 7 blue marbles. What is the probability of drawing a red marble at random?',ARRAY['3/10','7/10','3/7','1/3']::text[],ARRAY['3/10','7/10','3/7','1/3']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'There are 3 red marbles out of 10 total, so the probability is 3/10.','There are 3 red marbles out of 10 total, so the probability is 3/10.','When outcomes are equally likely, probability equals favorable outcomes over total outcomes. Here every marble is equally likely to be drawn. The total is the sum of all marbles, not just one color.','When outcomes are equally likely, probability equals favorable outcomes over total outcomes. Here every marble is equally likely to be drawn. The total is the sum of all marbles, not just one color.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-probability-i-1','data','data:probability','data-probability-i-1','intermediate','mcq','If the probability that it rains tomorrow is 0.3, what is the probability that it does not rain?','If the probability that it rains tomorrow is 0.3, what is the probability that it does not rain?',ARRAY['0.7','0.3','0.5','1.3']::text[],ARRAY['0.7','0.3','0.5','1.3']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The complement of an event is 1 minus its probability, so 1 - 0.3 = 0.7.','The complement of an event is 1 minus its probability, so 1 - 0.3 = 0.7.','The complement of an event is everything that is not that event. Because something must happen, the probability of an event and its complement add up to 1. So the probability of ''not rain'' is 1 minus the probability of rain.','The complement of an event is everything that is not that event. Because something must happen, the probability of an event and its complement add up to 1. So the probability of ''not rain'' is 1 minus the probability of rain.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-probability-i-2','data','data:probability','data-probability-i-2','intermediate','mcq','You flip a fair coin twice. What is the probability of getting heads both times?','You flip a fair coin twice. What is the probability of getting heads both times?',ARRAY['1/4','1/2','1/3','2/4']::text[],ARRAY['1/4','1/2','1/3','2/4']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Each flip is independent with probability 1/2, so 1/2 x 1/2 = 1/4.','Each flip is independent with probability 1/2, so 1/2 x 1/2 = 1/4.','Two events are independent when one does not affect the other. For independent events, the probability that both happen is the product of their individual probabilities. Two coin flips are independent, so you multiply 1/2 by 1/2.','Two events are independent when one does not affect the other. For independent events, the probability that both happen is the product of their individual probabilities. Two coin flips are independent, so you multiply 1/2 by 1/2.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-probability-a-1','data','data:probability','data-probability-a-1','advanced','mcq','A test for a rare disease is 99% accurate, but the disease affects only 1 in 1000 people. If someone tests positive, the chance they actually have the disease is closest to:','A test for a rare disease is 99% accurate, but the disease affects only 1 in 1000 people. If someone tests positive, the chance they actually have the disease is closest to:',ARRAY['About 9%','About 99%','About 50%','About 1%']::text[],ARRAY['About 9%','About 99%','About 50%','About 1%']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Because the disease is rare, false positives from the healthy majority outnumber true positives, so the true-positive rate is only around 9%.','Because the disease is rare, false positives from the healthy majority outnumber true positives, so the true-positive rate is only around 9%.','When a condition is rare, even an accurate test produces many false positives relative to true positives, a result known as the base rate fallacy. The chance of truly having the condition given a positive test depends heavily on how common the condition is. This is why screening rare events can be misleading without considering the base rate.','When a condition is rare, even an accurate test produces many false positives relative to true positives, a result known as the base rate fallacy. The chance of truly having the condition given a positive test depends heavily on how common the condition is. This is why screening rare events can be misleading without considering the base rate.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-probability-a-2','data','data:probability','data-probability-a-2','advanced','truefalse','True or false: After a fair coin lands heads five times in a row, the next flip is more likely to be tails.','True or false: After a fair coin lands heads five times in a row, the next flip is more likely to be tails.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Each flip is independent, so the probability of tails remains 1/2 regardless of past results.','Each flip is independent, so the probability of tails remains 1/2 regardless of past results.','The gambler''s fallacy is the mistaken belief that past independent outcomes change future probabilities. A fair coin has no memory, so each flip stays at 1/2 no matter what came before. Past streaks do not make a balancing outcome more likely.','The gambler''s fallacy is the mistaken belief that past independent outcomes change future probabilities. A fair coin has no memory, so each flip stays at 1/2 no matter what came before. Past streaks do not make a balancing outcome more likely.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-charts-b-1','data','data:charts','data-charts-b-1','beginner','mcq','A bar chart shows sales: Monday 10, Tuesday 25, Wednesday 15, Thursday 30. Which day had the highest sales?','A bar chart shows sales: Monday 10, Tuesday 25, Wednesday 15, Thursday 30. Which day had the highest sales?',ARRAY['Thursday','Tuesday','Wednesday','Monday']::text[],ARRAY['Thursday','Tuesday','Wednesday','Monday']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Thursday''s value of 30 is the largest, so its bar is the tallest.','Thursday''s value of 30 is the largest, so its bar is the tallest.','A bar chart represents values with the heights or lengths of bars, making comparisons across categories easy. The tallest bar corresponds to the largest value. Bar charts are best for comparing separate categories rather than showing trends over continuous time.','A bar chart represents values with the heights or lengths of bars, making comparisons across categories easy. The tallest bar corresponds to the largest value. Bar charts are best for comparing separate categories rather than showing trends over continuous time.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-charts-b-2','data','data:charts','data-charts-b-2','beginner','mcq','A pie chart of a budget shows Rent 50%, Food 25%, Transport 15%, and Savings as the remainder. What percentage is Savings?','A pie chart of a budget shows Rent 50%, Food 25%, Transport 15%, and Savings as the remainder. What percentage is Savings?',ARRAY['10%','15%','25%','5%']::text[],ARRAY['10%','15%','25%','5%']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The slices must sum to 100%, so Savings is 100 - 50 - 25 - 15 = 10%.','The slices must sum to 100%, so Savings is 100 - 50 - 25 - 15 = 10%.','A pie chart shows how a whole is divided into parts, with each slice proportional to its share. All slices together must add up to 100%. To find a missing slice, subtract the known slices from 100%.','A pie chart shows how a whole is divided into parts, with each slice proportional to its share. All slices together must add up to 100%. To find a missing slice, subtract the known slices from 100%.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-charts-i-1','data','data:charts','data-charts-i-1','intermediate','mcq','A line graph shows monthly revenue rising from 100 in January to 160 in March. What is the overall trend?','A line graph shows monthly revenue rising from 100 in January to 160 in March. What is the overall trend?',ARRAY['Increasing','Decreasing','Flat','Cyclical with no net change']::text[],ARRAY['Increasing','Decreasing','Flat','Cyclical with no net change']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Revenue moves upward from 100 to 160 over the period, indicating an increasing trend.','Revenue moves upward from 100 to 160 over the period, indicating an increasing trend.','A line graph connects data points over a continuous variable such as time, making trends easy to see. An upward slope shows growth and a downward slope shows decline. Reading the start and end points reveals the overall direction of change.','A line graph connects data points over a continuous variable such as time, making trends easy to see. An upward slope shows growth and a downward slope shows decline. Reading the start and end points reveals the overall direction of change.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-charts-i-2','data','data:charts','data-charts-i-2','intermediate','mcq','A bar chart''s vertical axis starts at 90 instead of 0, making a bar of 100 look twice as tall as a bar of 95. What problem does this create?','A bar chart''s vertical axis starts at 90 instead of 0, making a bar of 100 look twice as tall as a bar of 95. What problem does this create?',ARRAY['It exaggerates small differences between values','It makes the values easier to read accurately','It changes the actual data values','It has no effect on interpretation']::text[],ARRAY['It exaggerates small differences between values','It makes the values easier to read accurately','It changes the actual data values','It has no effect on interpretation']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A truncated axis that does not start at zero visually magnifies small differences, misleading the viewer.','A truncated axis that does not start at zero visually magnifies small differences, misleading the viewer.','When a bar chart''s value axis does not start at zero, the relative heights of bars no longer reflect the true ratios between values. Small differences can appear dramatic, which can mislead viewers. Always check the axis range before judging how big a difference really is.','When a bar chart''s value axis does not start at zero, the relative heights of bars no longer reflect the true ratios between values. Small differences can appear dramatic, which can mislead viewers. Always check the axis range before judging how big a difference really is.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-charts-a-1','data','data:charts','data-charts-a-1','advanced','mcq','A scatter plot shows that as study hours increase, exam scores tend to increase, with points sloping upward. This pattern indicates:','A scatter plot shows that as study hours increase, exam scores tend to increase, with points sloping upward. This pattern indicates:',ARRAY['A positive correlation','A negative correlation','No correlation','That studying causes higher scores for certain']::text[],ARRAY['A positive correlation','A negative correlation','No correlation','That studying causes higher scores for certain']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Points sloping upward together indicate a positive correlation between the two variables.','Points sloping upward together indicate a positive correlation between the two variables.','A scatter plot displays the relationship between two numeric variables, one on each axis. An upward pattern is a positive correlation and a downward pattern is a negative correlation. Correlation describes association only and does not by itself prove that one variable causes the other.','A scatter plot displays the relationship between two numeric variables, one on each axis. An upward pattern is a positive correlation and a downward pattern is a negative correlation. Correlation describes association only and does not by itself prove that one variable causes the other.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-charts-a-2','data','data:charts','data-charts-a-2','advanced','mcq','A histogram of incomes has a long tail stretching to the right toward very high values. This distribution is described as:','A histogram of incomes has a long tail stretching to the right toward very high values. This distribution is described as:',ARRAY['Right-skewed','Left-skewed','Symmetric','Uniform']::text[],ARRAY['Right-skewed','Left-skewed','Symmetric','Uniform']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A tail extending toward the high (right) end of the axis indicates a right-skewed distribution.','A tail extending toward the high (right) end of the axis indicates a right-skewed distribution.','A histogram groups numeric data into bins and shows their frequencies as bars. Skew refers to the direction of a long tail: a right-skewed distribution has a tail toward higher values. In right-skewed data the mean is typically pulled above the median by the high values.','A histogram groups numeric data into bins and shows their frequencies as bars. Skew refers to the direction of a long tail: a right-skewed distribution has a tail toward higher values. In right-skewed data the mean is typically pulled above the median by the high values.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-studies-b-1','data','data:studies','data-studies-b-1','beginner','truefalse','True or false: A survey of only a company''s own employees is a reliable way to measure the general public''s opinion of that company.','True or false: A survey of only a company''s own employees is a reliable way to measure the general public''s opinion of that company.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Employees are not representative of the general public, so the sample is biased.','Employees are not representative of the general public, so the sample is biased.','A sample should represent the larger population you want to study. When a sample is drawn from an unrepresentative group, the results suffer from selection bias. Conclusions about the public require a sample that actually reflects the public.','A sample should represent the larger population you want to study. When a sample is drawn from an unrepresentative group, the results suffer from selection bias. Conclusions about the public require a sample that actually reflects the public.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-studies-b-2','data','data:studies','data-studies-b-2','beginner','mcq','Ice cream sales and drowning deaths both rise in summer. What is the most likely explanation?','Ice cream sales and drowning deaths both rise in summer. What is the most likely explanation?',ARRAY['A third factor, hot weather, drives both','Ice cream causes drowning','Drowning causes ice cream sales','The link is impossible to explain']::text[],ARRAY['A third factor, hot weather, drives both','Ice cream causes drowning','Drowning causes ice cream sales','The link is impossible to explain']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Warm weather independently increases both swimming and ice cream consumption, creating a spurious link.','Warm weather independently increases both swimming and ice cream consumption, creating a spurious link.','Two things can rise and fall together without one causing the other. Often a third variable, called a confounder, influences both. Correlation alone does not establish causation.','Two things can rise and fall together without one causing the other. Often a third variable, called a confounder, influences both. Correlation alone does not establish causation.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-studies-i-1','data','data:studies','data-studies-i-1','intermediate','mcq','A study finds people who drink coffee live longer, but coffee drinkers also exercise more. Exercise here is best described as:','A study finds people who drink coffee live longer, but coffee drinkers also exercise more. Exercise here is best described as:',ARRAY['A confounding variable','The outcome variable','A random error','A placebo effect']::text[],ARRAY['A confounding variable','The outcome variable','A random error','A placebo effect']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Exercise is associated with both coffee drinking and longevity, so it confounds the observed link.','Exercise is associated with both coffee drinking and longevity, so it confounds the observed link.','A confounding variable is associated with both the supposed cause and the outcome, distorting the apparent relationship. If confounders are not controlled, an observed association may be misleading. Well-designed studies try to account for confounders before claiming a cause.','A confounding variable is associated with both the supposed cause and the outcome, distorting the apparent relationship. If confounders are not controlled, an observed association may be misleading. Well-designed studies try to account for confounders before claiming a cause.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-studies-i-2','data','data:studies','data-studies-i-2','intermediate','mcq','Why is a randomized controlled trial considered stronger evidence of causation than an observational study?','Why is a randomized controlled trial considered stronger evidence of causation than an observational study?',ARRAY['Random assignment balances out confounding factors between groups','It always uses a larger sample size','It avoids using any statistics','It guarantees the result is true']::text[],ARRAY['Random assignment balances out confounding factors between groups','It always uses a larger sample size','It avoids using any statistics','It guarantees the result is true']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Randomly assigning participants tends to balance known and unknown confounders across groups, isolating the treatment''s effect.','Randomly assigning participants tends to balance known and unknown confounders across groups, isolating the treatment''s effect.','In a randomized controlled trial, participants are assigned to treatment or control groups by chance. Randomization tends to distribute confounding factors evenly, so differences in outcomes can be attributed to the treatment. Observational studies lack this control, making causal claims weaker.','In a randomized controlled trial, participants are assigned to treatment or control groups by chance. Randomization tends to distribute confounding factors evenly, so differences in outcomes can be attributed to the treatment. Observational studies lack this control, making causal claims weaker.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-studies-a-1','data','data:studies','data-studies-a-1','advanced','mcq','A weight-loss ad reports an ''average loss of 20 pounds,'' but most participants lost about 5 pounds while a few lost over 60. Which is the likely issue?','A weight-loss ad reports an ''average loss of 20 pounds,'' but most participants lost about 5 pounds while a few lost over 60. Which is the likely issue?',ARRAY['The mean is inflated by a few extreme results, so the median would be more honest','The median is too high to report','The data must be fabricated','Twenty pounds is the most common result']::text[],ARRAY['The mean is inflated by a few extreme results, so the median would be more honest','The median is too high to report','The data must be fabricated','Twenty pounds is the most common result']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A few very large losses pull the mean upward, making it unrepresentative of a typical participant.','A few very large losses pull the mean upward, making it unrepresentative of a typical participant.','When results are skewed, the mean can be dominated by a few extreme values and overstate the typical outcome. Advertisers may choose the mean precisely because it sounds more impressive. The median better reflects what a typical participant experienced.','When results are skewed, the mean can be dominated by a few extreme values and overstate the typical outcome. Advertisers may choose the mean precisely because it sounds more impressive. The median better reflects what a typical participant experienced.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-data-studies-a-2','data','data:studies','data-studies-a-2','advanced','truefalse','True or false: An online poll where readers choose whether to respond can be safely generalized to the whole population.','True or false: An online poll where readers choose whether to respond can be safely generalized to the whole population.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Self-selected respondents differ systematically from non-responders, producing self-selection bias.','Self-selected respondents differ systematically from non-responders, producing self-selection bias.','Voluntary-response or self-selected samples include only people motivated enough to participate, who often hold stronger or unusual opinions. This creates self-selection bias that distorts the results. Reliable generalization requires a randomly drawn, representative sample rather than whoever chooses to respond.','Voluntary-response or self-selected samples include only people motivated enough to participate, who often hold stronger or unusual opinions. This creates self-selection bias that distorts the results. Reliable generalization requires a randomly drawn, representative sample rather than whoever chooses to respond.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-listening-b-1','interpersonal','interpersonal:listening','interpersonal-listening-b-1','beginner','mcq','A coworker is explaining a problem they''re facing. Which behavior best demonstrates active listening?','A coworker is explaining a problem they''re facing. Which behavior best demonstrates active listening?',ARRAY['Paraphrasing what they said to confirm you understood','Quickly offering a solution before they finish','Checking your phone while nodding occasionally','Changing the subject to a similar problem you once had']::text[],ARRAY['Paraphrasing what they said to confirm you understood','Quickly offering a solution before they finish','Checking your phone while nodding occasionally','Changing the subject to a similar problem you once had']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Paraphrasing shows the speaker you''ve genuinely processed their message and lets them correct any misunderstanding.','Paraphrasing shows the speaker you''ve genuinely processed their message and lets them correct any misunderstanding.','Active listening means fully concentrating on the speaker rather than just waiting to reply. A core technique is reflecting or paraphrasing the speaker''s words back to them. This confirms understanding and signals that you value what they said.','Active listening means fully concentrating on the speaker rather than just waiting to reply. A core technique is reflecting or paraphrasing the speaker''s words back to them. This confirms understanding and signals that you value what they said.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-listening-b-2','interpersonal','interpersonal:listening','interpersonal-listening-b-2','beginner','truefalse','Interrupting someone to finish their sentence shows you''re engaged and listening well.','Interrupting someone to finish their sentence shows you''re engaged and listening well.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Interrupting signals impatience and shifts focus to you rather than letting the speaker complete their own thought.','Interrupting signals impatience and shifts focus to you rather than letting the speaker complete their own thought.','Letting people finish their thoughts is a foundation of respectful listening. Interrupting, even with good intentions, can make speakers feel unheard or rushed. Allowing brief silences gives them space to express themselves fully.','Letting people finish their thoughts is a foundation of respectful listening. Interrupting, even with good intentions, can make speakers feel unheard or rushed. Allowing brief silences gives them space to express themselves fully.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-listening-i-1','interpersonal','interpersonal:listening','interpersonal-listening-i-1','intermediate','mcq','A teammate says, ''I guess I''ll just handle the launch alone, like always.'' What''s the best active-listening response?','A teammate says, ''I guess I''ll just handle the launch alone, like always.'' What''s the best active-listening response?',ARRAY['It sounds like you''re feeling unsupported on this. Can you tell me more?','You''re not alone, stop exaggerating.','Okay, let me know if you need anything.','Everyone is busy, that''s just how launches go.']::text[],ARRAY['It sounds like you''re feeling unsupported on this. Can you tell me more?','You''re not alone, stop exaggerating.','Okay, let me know if you need anything.','Everyone is busy, that''s just how launches go.']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Reflecting the underlying feeling invites the speaker to share more and shows you heard the emotion behind the words.','Reflecting the underlying feeling invites the speaker to share more and shows you heard the emotion behind the words.','Active listening includes attending to the emotion beneath the literal words. Reflecting feelings (''it sounds like you''re feeling...'') validates the person and opens dialogue. This is more effective than dismissing, minimizing, or offering a quick fix.','Active listening includes attending to the emotion beneath the literal words. Reflecting feelings (''it sounds like you''re feeling...'') validates the person and opens dialogue. This is more effective than dismissing, minimizing, or offering a quick fix.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-listening-i-2','interpersonal','interpersonal:listening','interpersonal-listening-i-2','intermediate','mcq','Which question type best encourages someone to elaborate during a conversation?','Which question type best encourages someone to elaborate during a conversation?',ARRAY['An open-ended question like ''What happened next?''','A closed yes/no question like ''Did that work?''','A leading question like ''You agree it was fine, right?''','A rapid series of short factual questions']::text[],ARRAY['An open-ended question like ''What happened next?''','A closed yes/no question like ''Did that work?''','A leading question like ''You agree it was fine, right?''','A rapid series of short factual questions']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Open-ended questions invite fuller responses and let the speaker steer the depth and direction of their answer.','Open-ended questions invite fuller responses and let the speaker steer the depth and direction of their answer.','Open-ended questions begin with words like what, how, or tell me, and cannot be answered with a single word. They encourage the speaker to elaborate and reveal more context. Closed and leading questions tend to shut down or steer the conversation.','Open-ended questions begin with words like what, how, or tell me, and cannot be answered with a single word. They encourage the speaker to elaborate and reveal more context. Closed and leading questions tend to shut down or steer the conversation.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-listening-a-1','interpersonal','interpersonal:listening','interpersonal-listening-a-1','advanced','mcq','In a tense meeting, a stakeholder''s words say ''It''s fine'' but their tone is clipped and arms are crossed. What does skilled listening call for?','In a tense meeting, a stakeholder''s words say ''It''s fine'' but their tone is clipped and arms are crossed. What does skilled listening call for?',ARRAY['Gently naming the mismatch: ''You say it''s fine, but I sense some hesitation—what''s on your mind?''','Taking ''it''s fine'' at face value and moving on','Pointing out publicly that their body language is negative','Ignoring the cue to avoid making things awkward']::text[],ARRAY['Gently naming the mismatch: ''You say it''s fine, but I sense some hesitation—what''s on your mind?''','Taking ''it''s fine'' at face value and moving on','Pointing out publicly that their body language is negative','Ignoring the cue to avoid making things awkward']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Gently surfacing the gap between words and nonverbal cues invites honesty without putting the person on the defensive.','Gently surfacing the gap between words and nonverbal cues invites honesty without putting the person on the defensive.','When verbal and nonverbal messages conflict, the nonverbal signal often carries the truer feeling. Skilled listeners tactfully name the discrepancy to invite the real concern into the open. Doing this privately and curiously, rather than accusingly, preserves the person''s dignity.','When verbal and nonverbal messages conflict, the nonverbal signal often carries the truer feeling. Skilled listeners tactfully name the discrepancy to invite the real concern into the open. Doing this privately and curiously, rather than accusingly, preserves the person''s dignity.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-listening-a-2','interpersonal','interpersonal:listening','interpersonal-listening-a-2','advanced','mcq','You notice you''re mentally rehearsing your rebuttal while a colleague is still talking. What''s the most effective self-correction?','You notice you''re mentally rehearsing your rebuttal while a colleague is still talking. What''s the most effective self-correction?',ARRAY['Refocus attention on understanding their point before forming any response','Interrupt now so you don''t forget your counterargument','Tune out and wait for them to finish so you can speak','Write down your rebuttal in detail as they talk']::text[],ARRAY['Refocus attention on understanding their point before forming any response','Interrupt now so you don''t forget your counterargument','Tune out and wait for them to finish so you can speak','Write down your rebuttal in detail as they talk']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Listening to understand rather than to reply is what makes comprehension and connection possible.','Listening to understand rather than to reply is what makes comprehension and connection possible.','A common barrier to listening is preparing your response instead of absorbing the other person''s message. This ''listening to reply'' splits your attention and causes you to miss meaning. The fix is to suspend your own agenda and prioritize understanding first.','A common barrier to listening is preparing your response instead of absorbing the other person''s message. This ''listening to reply'' splits your attention and causes you to miss meaning. The fix is to suspend your own agenda and prioritize understanding first.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-feedback-b-1','interpersonal','interpersonal:feedback','interpersonal-feedback-b-1','beginner','mcq','Which feedback is most useful because it focuses on specific behavior?','Which feedback is most useful because it focuses on specific behavior?',ARRAY['In the meeting you interrupted Sam twice before he finished his point.','You''re kind of rude in meetings.','You have a bad attitude.','People don''t really like working with you.']::text[],ARRAY['In the meeting you interrupted Sam twice before he finished his point.','You''re kind of rude in meetings.','You have a bad attitude.','People don''t really like working with you.']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Naming the specific observable behavior makes the feedback clear and actionable rather than a vague character judgment.','Naming the specific observable behavior makes the feedback clear and actionable rather than a vague character judgment.','Effective feedback targets specific behaviors, not personality or character. Describing exactly what happened (''you interrupted twice'') gives the person something concrete to change. Vague labels like ''rude'' or ''bad attitude'' feel like attacks and offer no clear path forward.','Effective feedback targets specific behaviors, not personality or character. Describing exactly what happened (''you interrupted twice'') gives the person something concrete to change. Vague labels like ''rude'' or ''bad attitude'' feel like attacks and offer no clear path forward.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-feedback-b-2','interpersonal','interpersonal:feedback','interpersonal-feedback-b-2','beginner','truefalse','Positive feedback should also be specific, not just a general ''good job.''','Positive feedback should also be specific, not just a general ''good job.''',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Specific praise tells the person exactly what to keep doing, making it more meaningful and reinforcing than a vague compliment.','Specific praise tells the person exactly what to keep doing, making it more meaningful and reinforcing than a vague compliment.','Feedback principles apply to praise as well as criticism. Specific positive feedback, such as naming the exact action that helped, reinforces the behavior you want repeated. A generic ''good job'' feels nice but gives little guidance on what to continue.','Feedback principles apply to praise as well as criticism. Specific positive feedback, such as naming the exact action that helped, reinforces the behavior you want repeated. A generic ''good job'' feels nice but gives little guidance on what to continue.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-feedback-i-1','interpersonal','interpersonal:feedback','interpersonal-feedback-i-1','intermediate','mcq','A report missed a deadline. Which opener delivers the concern most constructively?','A report missed a deadline. Which opener delivers the concern most constructively?',ARRAY['When the report came in two days late, I had to delay the client update.','You always miss your deadlines.','Why can''t you ever get things in on time?','You made me look bad in front of the client.']::text[],ARRAY['When the report came in two days late, I had to delay the client update.','You always miss your deadlines.','Why can''t you ever get things in on time?','You made me look bad in front of the client.']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'An ''I'' statement tied to a specific event and its impact avoids blame while clearly communicating the consequence.','An ''I'' statement tied to a specific event and its impact avoids blame while clearly communicating the consequence.','''I'' statements describe the situation, your reaction, and the impact without accusing the other person. Phrasing like ''when X happened, the effect was Y'' keeps focus on facts and consequences. This reduces defensiveness compared with ''you'' accusations and absolutes like ''always.''','''I'' statements describe the situation, your reaction, and the impact without accusing the other person. Phrasing like ''when X happened, the effect was Y'' keeps focus on facts and consequences. This reduces defensiveness compared with ''you'' accusations and absolutes like ''always.''',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-feedback-i-2','interpersonal','interpersonal:feedback','interpersonal-feedback-i-2','intermediate','mcq','When is feedback generally most effective?','When is feedback generally most effective?',ARRAY['Soon after the event, in a private and appropriate setting','Saved up and delivered all at once in the annual review','Immediately, in front of the whole team for emphasis','Only when the person specifically asks for it']::text[],ARRAY['Soon after the event, in a private and appropriate setting','Saved up and delivered all at once in the annual review','Immediately, in front of the whole team for emphasis','Only when the person specifically asks for it']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Timely, private feedback lets the person recall and act on the specifics while protecting their dignity.','Timely, private feedback lets the person recall and act on the specifics while protecting their dignity.','Feedback works best when it is timely, given close enough to the event that details are fresh. Corrective feedback should typically be delivered privately to avoid embarrassment. Saving issues for a single annual review makes them harder to recall and to address.','Feedback works best when it is timely, given close enough to the event that details are fresh. Corrective feedback should typically be delivered privately to avoid embarrassment. Saving issues for a single annual review makes them harder to recall and to address.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-feedback-a-1','interpersonal','interpersonal:feedback','interpersonal-feedback-a-1','advanced','mcq','A high performer reacts defensively to your corrective feedback. What''s the best next move?','A high performer reacts defensively to your corrective feedback. What''s the best next move?',ARRAY['Acknowledge their reaction and ask for their perspective on the situation','Repeat your point more firmly until they accept it','Drop the issue to keep the peace','Remind them of your authority to give the feedback']::text[],ARRAY['Acknowledge their reaction and ask for their perspective on the situation','Repeat your point more firmly until they accept it','Drop the issue to keep the peace','Remind them of your authority to give the feedback']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Inviting their perspective turns feedback into a two-way dialogue and lowers defensiveness so the message can land.','Inviting their perspective turns feedback into a two-way dialogue and lowers defensiveness so the message can land.','Feedback is most effective as a dialogue, not a verdict. When someone reacts defensively, acknowledging their emotion and seeking their view helps them feel respected and reduces threat. This collaborative stance increases the odds they will actually consider the feedback.','Feedback is most effective as a dialogue, not a verdict. When someone reacts defensively, acknowledging their emotion and seeking their view helps them feel respected and reduces threat. This collaborative stance increases the odds they will actually consider the feedback.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-feedback-a-2','interpersonal','interpersonal:feedback','interpersonal-feedback-a-2','advanced','mcq','Why is the traditional ''praise-criticism-praise sandwich'' often criticized as a feedback method?','Why is the traditional ''praise-criticism-praise sandwich'' often criticized as a feedback method?',ARRAY['It can dilute the core message and make praise feel insincere','It is too direct and harsh for most people','It removes all positive feedback from the conversation','It only works in written form, never in person']::text[],ARRAY['It can dilute the core message and make praise feel insincere','It is too direct and harsh for most people','It removes all positive feedback from the conversation','It only works in written form, never in person']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Burying criticism between compliments can obscure the real point and train people to distrust your praise.','Burying criticism between compliments can obscure the real point and train people to distrust your praise.','The feedback sandwich aims to soften criticism but often backfires. Recipients may miss the actual concern or learn to brace whenever they hear praise, eroding its value. Clear, respectful, direct feedback that separates genuine praise from development points is usually more honest and effective.','The feedback sandwich aims to soften criticism but often backfires. Recipients may miss the actual concern or learn to brace whenever they hear praise, eroding its value. Clear, respectful, direct feedback that separates genuine praise from development points is usually more honest and effective.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-negotiation-b-1','interpersonal','interpersonal:negotiation','interpersonal-negotiation-b-1','beginner','mcq','In negotiation, what is the difference between a position and an interest?','In negotiation, what is the difference between a position and an interest?',ARRAY['A position is what someone demands; an interest is the underlying need behind it','A position is flexible; an interest is fixed and non-negotiable','They mean the same thing in practice','A position is the other side''s need; an interest is your own demand']::text[],ARRAY['A position is what someone demands; an interest is the underlying need behind it','A position is flexible; an interest is fixed and non-negotiable','They mean the same thing in practice','A position is the other side''s need; an interest is your own demand']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Positions are the stated demands, while interests are the deeper motivations that often allow for creative solutions.','Positions are the stated demands, while interests are the deeper motivations that often allow for creative solutions.','A position is the specific thing a party says they want, such as a price or deadline. An interest is the underlying need or concern driving that demand. Focusing on interests rather than positions opens room for solutions that satisfy both sides.','A position is the specific thing a party says they want, such as a price or deadline. An interest is the underlying need or concern driving that demand. Focusing on interests rather than positions opens room for solutions that satisfy both sides.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-negotiation-b-2','interpersonal','interpersonal:negotiation','interpersonal-negotiation-b-2','beginner','truefalse','Your BATNA is your best alternative to a negotiated agreement—what you''ll do if no deal is reached.','Your BATNA is your best alternative to a negotiated agreement—what you''ll do if no deal is reached.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'BATNA stands for Best Alternative To a Negotiated Agreement and defines your fallback if the talk fails.','BATNA stands for Best Alternative To a Negotiated Agreement and defines your fallback if the talk fails.','BATNA is the course of action you''ll take if the negotiation produces no agreement. Knowing your BATNA tells you when to accept a deal and when to walk away. A strong BATNA gives you more leverage and confidence at the table.','BATNA is the course of action you''ll take if the negotiation produces no agreement. Knowing your BATNA tells you when to accept a deal and when to walk away. A strong BATNA gives you more leverage and confidence at the table.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-negotiation-i-1','interpersonal','interpersonal:negotiation','interpersonal-negotiation-i-1','intermediate','mcq','Two teams both claim they need the single shared meeting room at 10 a.m. What''s the most interest-based approach?','Two teams both claim they need the single shared meeting room at 10 a.m. What''s the most interest-based approach?',ARRAY['Ask each team why they need that slot to find a solution that meets both needs','Give it to whoever asked first and tell the other to deal with it','Split the room in half so each gets part of it','Flip a coin to decide who gets the room']::text[],ARRAY['Ask each team why they need that slot to find a solution that meets both needs','Give it to whoever asked first and tell the other to deal with it','Split the room in half so each gets part of it','Flip a coin to decide who gets the room']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Exploring the reasons behind each demand can reveal options, like a different time or format, that satisfy both teams.','Exploring the reasons behind each demand can reveal options, like a different time or format, that satisfy both teams.','When positions clash, asking ''why'' uncovers the underlying interests. One team may need the room for a client call while the other just needs any quiet space. Understanding these differences often reveals a solution neither side saw from their stated positions.','When positions clash, asking ''why'' uncovers the underlying interests. One team may need the room for a client call while the other just needs any quiet space. Understanding these differences often reveals a solution neither side saw from their stated positions.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-negotiation-i-2','interpersonal','interpersonal:negotiation','interpersonal-negotiation-i-2','intermediate','mcq','What does it mean to use objective criteria in a negotiation?','What does it mean to use objective criteria in a negotiation?',ARRAY['Grounding the deal in fair, independent standards like market rates or data','Insisting on whatever number you decided in advance','Letting the more senior person set all the terms','Splitting every difference exactly down the middle']::text[],ARRAY['Grounding the deal in fair, independent standards like market rates or data','Insisting on whatever number you decided in advance','Letting the more senior person set all the terms','Splitting every difference exactly down the middle']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Objective criteria let both parties measure fairness against an external standard instead of a contest of wills.','Objective criteria let both parties measure fairness against an external standard instead of a contest of wills.','Principled negotiation favors objective criteria such as market value, expert opinion, or precedent. Anchoring terms to independent standards makes outcomes feel fair and defensible. This shifts the discussion from a battle of stubbornness to a search for a legitimate benchmark.','Principled negotiation favors objective criteria such as market value, expert opinion, or precedent. Anchoring terms to independent standards makes outcomes feel fair and defensible. This shifts the discussion from a battle of stubbornness to a search for a legitimate benchmark.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-negotiation-a-1','interpersonal','interpersonal:negotiation','interpersonal-negotiation-a-1','advanced','mcq','A counterpart opens with an extreme, aggressive demand to anchor the talk. What''s the strongest response?','A counterpart opens with an extreme, aggressive demand to anchor the talk. What''s the strongest response?',ARRAY['Refuse to treat the anchor as legitimate and re-anchor with your own well-justified standard','Immediately counter near their number to seem reasonable','Accept it to avoid conflict and preserve the relationship','Walk out of the negotiation entirely on principle']::text[],ARRAY['Refuse to treat the anchor as legitimate and re-anchor with your own well-justified standard','Immediately counter near their number to seem reasonable','Accept it to avoid conflict and preserve the relationship','Walk out of the negotiation entirely on principle']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Declining to engage with an extreme anchor and offering your own criteria-based number prevents the demand from skewing the deal.','Declining to engage with an extreme anchor and offering your own criteria-based number prevents the demand from skewing the deal.','Anchoring is a tactic where the first number strongly influences the final outcome. To counter an extreme anchor, you avoid negotiating off of it and instead introduce your own figure backed by objective criteria. This resets the frame around fairness rather than the other side''s extreme.','Anchoring is a tactic where the first number strongly influences the final outcome. To counter an extreme anchor, you avoid negotiating off of it and instead introduce your own figure backed by objective criteria. This resets the frame around fairness rather than the other side''s extreme.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-negotiation-a-2','interpersonal','interpersonal:negotiation','interpersonal-negotiation-a-2','advanced','mcq','How can a negotiator create a more integrative (win-win) outcome rather than a purely distributive one?','How can a negotiator create a more integrative (win-win) outcome rather than a purely distributive one?',ARRAY['Identify differing priorities and trade across issues so each side gains on what matters most to them','Focus on claiming the largest possible share of a fixed pie','Hide all information so the other side can''t gain leverage','Make concessions only when threatened']::text[],ARRAY['Identify differing priorities and trade across issues so each side gains on what matters most to them','Focus on claiming the largest possible share of a fixed pie','Hide all information so the other side can''t gain leverage','Make concessions only when threatened']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Trading across issues that each side values differently expands the total value rather than just dividing a fixed amount.','Trading across issues that each side values differently expands the total value rather than just dividing a fixed amount.','Distributive negotiation treats value as a fixed pie to be divided, while integrative negotiation expands it. By sharing priorities and trading low-value-to-you items for high-value-to-you ones, both parties can gain. Logrolling across issues with different importance to each side is a key way to create joint value.','Distributive negotiation treats value as a fixed pie to be divided, while integrative negotiation expands it. By sharing priorities and trading low-value-to-you items for high-value-to-you ones, both parties can gain. Logrolling across issues with different importance to each side is a key way to create joint value.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-conflict-b-1','interpersonal','interpersonal:conflict','interpersonal-conflict-b-1','beginner','mcq','A colleague comes to you visibly upset about a decision. What should you do first?','A colleague comes to you visibly upset about a decision. What should you do first?',ARRAY['Acknowledge their emotion before discussing the facts of the decision','Immediately explain why the decision was correct','Tell them not to take it personally','List all the reasons their reaction is an overreaction']::text[],ARRAY['Acknowledge their emotion before discussing the facts of the decision','Immediately explain why the decision was correct','Tell them not to take it personally','List all the reasons their reaction is an overreaction']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Acknowledging the emotion first helps the person feel heard and calms them enough to discuss the issue productively.','Acknowledging the emotion first helps the person feel heard and calms them enough to discuss the issue productively.','When someone is emotional, addressing the feeling comes before solving the problem. Acknowledging emotion (''I can see this really frustrated you'') helps the person feel understood. Only once they feel heard are they ready to engage with facts and solutions.','When someone is emotional, addressing the feeling comes before solving the problem. Acknowledging emotion (''I can see this really frustrated you'') helps the person feel understood. Only once they feel heard are they ready to engage with facts and solutions.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-conflict-b-2','interpersonal','interpersonal:conflict','interpersonal-conflict-b-2','beginner','truefalse','Empathy means agreeing with the other person''s point of view.','Empathy means agreeing with the other person''s point of view.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],1,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Empathy is understanding and acknowledging another''s feelings and perspective, which is distinct from agreeing with them.','Empathy is understanding and acknowledging another''s feelings and perspective, which is distinct from agreeing with them.','Empathy is the ability to understand and share the feelings of another person. You can empathize with someone''s frustration without agreeing that their conclusion is correct. Separating understanding from agreement lets you connect even during disagreement.','Empathy is the ability to understand and share the feelings of another person. You can empathize with someone''s frustration without agreeing that their conclusion is correct. Separating understanding from agreement lets you connect even during disagreement.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-conflict-i-1','interpersonal','interpersonal:conflict','interpersonal-conflict-i-1','intermediate','mcq','Two teammates are in an escalating argument and both turn to you. What''s the most de-escalating move?','Two teammates are in an escalating argument and both turn to you. What''s the most de-escalating move?',ARRAY['Acknowledge both viewpoints and refocus on the shared goal they both care about','Side with whoever has the stronger argument','Tell them both to calm down and stop being dramatic','Leave them to sort it out so you stay neutral']::text[],ARRAY['Acknowledge both viewpoints and refocus on the shared goal they both care about','Side with whoever has the stronger argument','Tell them both to calm down and stop being dramatic','Leave them to sort it out so you stay neutral']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Validating both perspectives and reorienting toward a common goal lowers defensiveness and creates room for resolution.','Validating both perspectives and reorienting toward a common goal lowers defensiveness and creates room for resolution.','De-escalation often starts with making each party feel heard rather than picking a winner. Naming the common goal reminds both people they are on the same side. Telling people to ''calm down'' usually backfires by dismissing their feelings.','De-escalation often starts with making each party feel heard rather than picking a winner. Naming the common goal reminds both people they are on the same side. Telling people to ''calm down'' usually backfires by dismissing their feelings.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-conflict-i-2','interpersonal','interpersonal:conflict','interpersonal-conflict-i-2','intermediate','mcq','Which statement best reflects empathy toward a frustrated customer?','Which statement best reflects empathy toward a frustrated customer?',ARRAY['I understand why this delay is frustrating—let''s figure out how to fix it.','There''s nothing I can do, it''s company policy.','Calm down, it''s really not a big deal.','Other customers don''t seem to have this problem.']::text[],ARRAY['I understand why this delay is frustrating—let''s figure out how to fix it.','There''s nothing I can do, it''s company policy.','Calm down, it''s really not a big deal.','Other customers don''t seem to have this problem.']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Naming and validating the customer''s frustration before moving to a solution shows genuine empathy and builds trust.','Naming and validating the customer''s frustration before moving to a solution shows genuine empathy and builds trust.','Empathic responses name the other person''s feeling and signal that it makes sense. This validation reduces defensiveness and shows you''re on their side. Dismissive replies that minimize or deflect tend to escalate frustration instead.','Empathic responses name the other person''s feeling and signal that it makes sense. This validation reduces defensiveness and shows you''re on their side. Dismissive replies that minimize or deflect tend to escalate frustration instead.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-conflict-a-1','interpersonal','interpersonal:conflict','interpersonal-conflict-a-1','advanced','mcq','A long-running conflict persists because each side keeps restating its demands. What''s the most effective intervention?','A long-running conflict persists because each side keeps restating its demands. What''s the most effective intervention?',ARRAY['Shift the conversation from positions to the underlying interests and needs of each side','Have the more senior person simply decide the outcome','Encourage both sides to compromise halfway on every point','Avoid the topic until tensions cool on their own']::text[],ARRAY['Shift the conversation from positions to the underlying interests and needs of each side','Have the more senior person simply decide the outcome','Encourage both sides to compromise halfway on every point','Avoid the topic until tensions cool on their own']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Surfacing the underlying needs behind entrenched demands reveals common ground and options that repeated positions hide.','Surfacing the underlying needs behind entrenched demands reveals common ground and options that repeated positions hide.','Entrenched conflicts often stall because parties argue positions rather than interests. Reframing toward the needs and concerns beneath those positions opens space for creative, mutually acceptable solutions. This separates the people from the problem and turns adversaries into joint problem-solvers.','Entrenched conflicts often stall because parties argue positions rather than interests. Reframing toward the needs and concerns beneath those positions opens space for creative, mutually acceptable solutions. This separates the people from the problem and turns adversaries into joint problem-solvers.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-interpersonal-conflict-a-2','interpersonal','interpersonal:conflict','interpersonal-conflict-a-2','advanced','mcq','You realize your own strong emotions are clouding your judgment during a heated disagreement. What''s the most emotionally intelligent response?','You realize your own strong emotions are clouding your judgment during a heated disagreement. What''s the most emotionally intelligent response?',ARRAY['Pause to name and regulate your own reaction before continuing the conversation','Push through and make your point while the emotion is strong','Blame the other person for provoking your reaction','Suppress the feeling entirely and pretend it isn''t there']::text[],ARRAY['Pause to name and regulate your own reaction before continuing the conversation','Push through and make your point while the emotion is strong','Blame the other person for provoking your reaction','Suppress the feeling entirely and pretend it isn''t there']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Recognizing and regulating your own emotion first restores the clear thinking needed to handle the conflict constructively.','Recognizing and regulating your own emotion first restores the clear thinking needed to handle the conflict constructively.','Self-awareness and self-regulation are core to emotional intelligence in conflict. Noticing your own emotional state and taking a brief pause prevents reactive escalation. Naming a feeling to yourself helps tame it, restoring your ability to respond thoughtfully rather than react.','Self-awareness and self-regulation are core to emotional intelligence in conflict. Noticing your own emotional state and taking a brief pause prevents reactive escalation. Naming a feeling to yourself helps tame it, restoring your ability to respond thoughtfully rather than react.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-structure-b-1','speaking','speaking:structure','speaking-structure-b-1','beginner','mcq','You have ten minutes to give an informative talk. Which overall structure makes it easiest for an audience to follow?','You have ten minutes to give an informative talk. Which overall structure makes it easiest for an audience to follow?',ARRAY['A clear opening that previews the main points, a body that develops them in order, and a closing that summarizes','A long string of facts delivered in whatever order they come to mind','Starting with your conclusion and never explaining how you reached it','Several unrelated anecdotes with no stated purpose']::text[],ARRAY['A clear opening that previews the main points, a body that develops them in order, and a closing that summarizes','A long string of facts delivered in whatever order they come to mind','Starting with your conclusion and never explaining how you reached it','Several unrelated anecdotes with no stated purpose']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A preview-body-summary structure tells the audience where you are going, takes them there, and reminds them where they have been.','A preview-body-summary structure tells the audience where you are going, takes them there, and reminds them where they have been.','Classic speech structure has three parts: tell them what you will say, say it, then tell them what you said. Previewing your points up front gives listeners a mental map. A clear close that restates the key takeaways helps the message stick because people remember beginnings and endings best.','Classic speech structure has three parts: tell them what you will say, say it, then tell them what you said. Previewing your points up front gives listeners a mental map. A clear close that restates the key takeaways helps the message stick because people remember beginnings and endings best.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-structure-b-2','speaking','speaking:structure','speaking-structure-b-2','beginner','truefalse','Signposting phrases such as ''first'', ''next'', and ''finally'' help listeners track where they are in your talk.','Signposting phrases such as ''first'', ''next'', and ''finally'' help listeners track where they are in your talk.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Signposts act as verbal headings that mark transitions and orient the audience without them needing to take notes.','Signposts act as verbal headings that mark transitions and orient the audience without them needing to take notes.','Listeners cannot rewind a live talk, so they rely on the speaker to flag transitions. Signposting words like first, next, and finally signal movement between points. They reduce the mental effort of following along and make a talk feel organized even when content is dense.','Listeners cannot rewind a live talk, so they rely on the speaker to flag transitions. Signposting words like first, next, and finally signal movement between points. They reduce the mental effort of following along and make a talk feel organized even when content is dense.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-structure-i-1','speaking','speaking:structure','speaking-structure-i-1','intermediate','mcq','You want your three key recommendations to be memorable. Which technique best supports that goal?','You want your three key recommendations to be memorable. Which technique best supports that goal?',ARRAY['Grouping them into a ''rule of three'' with parallel phrasing','Listing nine recommendations so nothing is left out','Burying them in the middle of a long paragraph','Mentioning each one only once, in passing']::text[],ARRAY['Grouping them into a ''rule of three'' with parallel phrasing','Listing nine recommendations so nothing is left out','Burying them in the middle of a long paragraph','Mentioning each one only once, in passing']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The rule of three with parallel phrasing is rhythmically satisfying and easy to recall, so three points land better than a longer list.','The rule of three with parallel phrasing is rhythmically satisfying and easy to recall, so three points land better than a longer list.','Audiences retain a small number of ideas, and sets of three feel complete and rhythmic. Parallel phrasing makes the trio sound deliberate and quotable. Trimming to three forces you to prioritize, which also sharpens the message.','Audiences retain a small number of ideas, and sets of three feel complete and rhythmic. Parallel phrasing makes the trio sound deliberate and quotable. Trimming to three forces you to prioritize, which also sharpens the message.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-structure-i-2','speaking','speaking:structure','speaking-structure-i-2','intermediate','mcq','Your data-heavy talk feels dry. What is the most effective way to make the numbers resonate?','Your data-heavy talk feels dry. What is the most effective way to make the numbers resonate?',ARRAY['Wrap a key statistic inside a short, concrete story about one affected person','Add more decimal places to every figure','Read every row of the spreadsheet aloud','Remove all context and present numbers in isolation']::text[],ARRAY['Wrap a key statistic inside a short, concrete story about one affected person','Add more decimal places to every figure','Read every row of the spreadsheet aloud','Remove all context and present numbers in isolation']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A concrete story gives an abstract statistic emotional weight and a human face, making it memorable.','A concrete story gives an abstract statistic emotional weight and a human face, making it memorable.','People connect with stories more readily than with raw data. Pairing a statistic with a single relatable example translates scale into something felt, not just understood. The narrative provides context that makes the number meaningful rather than forgettable.','People connect with stories more readily than with raw data. Pairing a statistic with a single relatable example translates scale into something felt, not just understood. The narrative provides context that makes the number meaningful rather than forgettable.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-structure-a-1','speaking','speaking:structure','speaking-structure-a-1','advanced','mcq','You are designing a persuasive keynote. Which narrative arc most reliably moves an audience toward action?','You are designing a persuasive keynote. Which narrative arc most reliably moves an audience toward action?',ARRAY['Establish the status quo, introduce a tension or problem, then resolve it with your proposed change and a call to action','Open with administrative housekeeping and end abruptly when time runs out','Present every counterargument first and never state your own position','Repeat a single claim louder each time without development']::text[],ARRAY['Establish the status quo, introduce a tension or problem, then resolve it with your proposed change and a call to action','Open with administrative housekeeping and end abruptly when time runs out','Present every counterargument first and never state your own position','Repeat a single claim louder each time without development']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A status-quo to tension to resolution arc creates a gap the audience wants closed, and your call to action closes it.','A status-quo to tension to resolution arc creates a gap the audience wants closed, and your call to action closes it.','Persuasive talks work like stories: they create a contrast between what is and what could be. The tension between those states generates the desire for change. Ending with a specific, achievable call to action channels that desire into a concrete next step.','Persuasive talks work like stories: they create a contrast between what is and what could be. The tension between those states generates the desire for change. Ending with a specific, achievable call to action channels that desire into a concrete next step.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-structure-a-2','speaking','speaking:structure','speaking-structure-a-2','advanced','truefalse','A ''callback'', where your closing returns to an image or phrase from your opening, can give a talk a satisfying sense of unity.','A ''callback'', where your closing returns to an image or phrase from your opening, can give a talk a satisfying sense of unity.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Returning to the opening image creates a frame that signals closure and rewards the audience for staying with you.','Returning to the opening image creates a frame that signals closure and rewards the audience for staying with you.','A callback bookends the talk by echoing something the audience already heard, which feels intentional and complete. It reinforces the central theme by revisiting it with the added meaning the talk has supplied. This sense of return is a reliable way to make an ending feel earned rather than abrupt.','A callback bookends the talk by echoing something the audience already heard, which feels intentional and complete. It reinforces the central theme by revisiting it with the added meaning the talk has supplied. This sense of return is a reliable way to make an ending feel earned rather than abrupt.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-delivery-b-1','speaking','speaking:delivery','speaking-delivery-b-1','beginner','mcq','You tend to rush when speaking. What is the simplest delivery fix to help the audience absorb your points?','You tend to rush when speaking. What is the simplest delivery fix to help the audience absorb your points?',ARRAY['Slow your pace and add deliberate pauses after key points','Speak even faster to fit everything in','Drop your volume to a near-whisper throughout','Read directly from a dense script in a monotone']::text[],ARRAY['Slow your pace and add deliberate pauses after key points','Speak even faster to fit everything in','Drop your volume to a near-whisper throughout','Read directly from a dense script in a monotone']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Slowing down and pausing gives listeners time to process and signals which ideas matter.','Slowing down and pausing gives listeners time to process and signals which ideas matter.','Nervous speakers often speed up, which overwhelms listeners. A measured pace plus pauses after important statements lets ideas land and adds emphasis. Silence is not dead air; it gives the audience a moment to absorb what you just said.','Nervous speakers often speed up, which overwhelms listeners. A measured pace plus pauses after important statements lets ideas land and adds emphasis. Silence is not dead air; it gives the audience a moment to absorb what you just said.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-delivery-b-2','speaking','speaking:delivery','speaking-delivery-b-2','beginner','truefalse','Making natural eye contact with individuals across the room helps build connection more than staring at your slides.','Making natural eye contact with individuals across the room helps build connection more than staring at your slides.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Eye contact signals confidence and engagement and makes listeners feel personally addressed.','Eye contact signals confidence and engagement and makes listeners feel personally addressed.','Eye contact creates a sense of one-to-one connection even in a large room. Looking at your slides or notes the whole time breaks that bond and reads as disengaged. Holding a gaze briefly with different people across the audience helps everyone feel included.','Eye contact creates a sense of one-to-one connection even in a large room. Looking at your slides or notes the whole time breaks that bond and reads as disengaged. Holding a gaze briefly with different people across the audience helps everyone feel included.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-delivery-i-1','speaking','speaking:delivery','speaking-delivery-i-1','intermediate','mcq','Your voice sounds flat and your audience is glazing over. Which vocal adjustment best re-engages them?','Your voice sounds flat and your audience is glazing over. Which vocal adjustment best re-engages them?',ARRAY['Vary your pitch, pace, and volume to match the meaning of what you are saying','Speak in a single steady tone to sound authoritative','Increase your speed uniformly for the rest of the talk','Lower your volume so people lean in for the entire section']::text[],ARRAY['Vary your pitch, pace, and volume to match the meaning of what you are saying','Speak in a single steady tone to sound authoritative','Increase your speed uniformly for the rest of the talk','Lower your volume so people lean in for the entire section']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Vocal variety in pitch, pace, and volume keeps attention and conveys emphasis and emotion.','Vocal variety in pitch, pace, and volume keeps attention and conveys emphasis and emotion.','A monotone delivery flattens meaning and quickly bores listeners. Varying pitch, pace, and volume highlights important ideas and signals shifts in tone. This vocal variety mirrors how we speak naturally in conversation and keeps the audience alert.','A monotone delivery flattens meaning and quickly bores listeners. Varying pitch, pace, and volume highlights important ideas and signals shifts in tone. This vocal variety mirrors how we speak naturally in conversation and keeps the audience alert.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-delivery-i-2','speaking','speaking:delivery','speaking-delivery-i-2','intermediate','mcq','You catch yourself saying ''um'' and ''like'' frequently. What is the most effective way to reduce filler words?','You catch yourself saying ''um'' and ''like'' frequently. What is the most effective way to reduce filler words?',ARRAY['Pause silently where you would have said a filler','Speak faster so the fillers slip by unnoticed','Add even more fillers so they sound intentional','Memorize the talk word for word and recite it rigidly']::text[],ARRAY['Pause silently where you would have said a filler','Speak faster so the fillers slip by unnoticed','Add even more fillers so they sound intentional','Memorize the talk word for word and recite it rigidly']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Fillers usually fill thinking time, so a deliberate silent pause replaces them while sounding more composed.','Fillers usually fill thinking time, so a deliberate silent pause replaces them while sounding more composed.','Filler words tend to appear when the brain needs a moment to find the next thought. Replacing that moment with a brief silence removes the filler and reads as confident and considered. Becoming comfortable with short pauses is the core skill behind clean delivery.','Filler words tend to appear when the brain needs a moment to find the next thought. Replacing that moment with a brief silence removes the filler and reads as confident and considered. Becoming comfortable with short pauses is the core skill behind clean delivery.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-delivery-a-1','speaking','speaking:delivery','speaking-delivery-a-1','advanced','mcq','You want gestures to strengthen rather than distract from your message. Which approach is best?','You want gestures to strengthen rather than distract from your message. Which approach is best?',ARRAY['Use purposeful gestures that illustrate specific ideas and keep hands at rest otherwise','Keep both hands rigidly at your sides the entire time','Make constant, repetitive hand movements regardless of content','Grip the lectern tightly so your hands never move']::text[],ARRAY['Use purposeful gestures that illustrate specific ideas and keep hands at rest otherwise','Keep both hands rigidly at your sides the entire time','Make constant, repetitive hand movements regardless of content','Grip the lectern tightly so your hands never move']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Gestures that map to specific ideas reinforce meaning, while a neutral resting position prevents nervous fidgeting from distracting.','Gestures that map to specific ideas reinforce meaning, while a neutral resting position prevents nervous fidgeting from distracting.','Effective gestures are deliberate and tied to what you are saying, such as showing size, sequence, or contrast. Constant or random movement becomes visual noise that competes with your words. A calm resting position between gestures lets each intentional movement carry weight.','Effective gestures are deliberate and tied to what you are saying, such as showing size, sequence, or contrast. Constant or random movement becomes visual noise that competes with your words. A calm resting position between gestures lets each intentional movement carry weight.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-delivery-a-2','speaking','speaking:delivery','speaking-delivery-a-2','advanced','truefalse','Strategic silence immediately before a key statement can heighten its impact more than rushing into it.','Strategic silence immediately before a key statement can heighten its impact more than rushing into it.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A pause before a key line creates anticipation and focuses attention on what follows.','A pause before a key line creates anticipation and focuses attention on what follows.','Silence is a powerful delivery tool, not a gap to fill. A deliberate pause before an important point builds tension and signals that something worth hearing is coming. Skilled speakers use these pauses to frame their most important lines and let them resonate.','Silence is a powerful delivery tool, not a gap to fill. A deliberate pause before an important point builds tension and signals that something worth hearing is coming. Skilled speakers use these pauses to frame their most important lines and let them resonate.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-nerves-b-1','speaking','speaking:nerves','speaking-nerves-b-1','beginner','mcq','Minutes before going on stage your heart is racing. Which technique most directly calms your nervous system?','Minutes before going on stage your heart is racing. Which technique most directly calms your nervous system?',ARRAY['Slow, deep diaphragmatic breathing','Holding your breath until you feel calmer','Drinking several cups of coffee for energy','Replaying every possible thing that could go wrong']::text[],ARRAY['Slow, deep diaphragmatic breathing','Holding your breath until you feel calmer','Drinking several cups of coffee for energy','Replaying every possible thing that could go wrong']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Slow diaphragmatic breathing lowers heart rate and signals the body to relax before you speak.','Slow diaphragmatic breathing lowers heart rate and signals the body to relax before you speak.','Pre-talk nerves trigger a fight-or-flight response that speeds the heart and shortens the breath. Slow, deep breathing from the diaphragm activates the body''s calming response and steadies the voice. A few measured breaths before you begin can noticeably reduce the physical symptoms of anxiety.','Pre-talk nerves trigger a fight-or-flight response that speeds the heart and shortens the breath. Slow, deep breathing from the diaphragm activates the body''s calming response and steadies the voice. A few measured breaths before you begin can noticeably reduce the physical symptoms of anxiety.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-nerves-b-2','speaking','speaking:nerves','speaking-nerves-b-2','beginner','truefalse','Thorough preparation and rehearsal generally reduce performance anxiety.','Thorough preparation and rehearsal generally reduce performance anxiety.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Knowing your material well removes uncertainty, which is a major source of nervousness.','Knowing your material well removes uncertainty, which is a major source of nervousness.','Much speaking anxiety comes from fear of forgetting or fumbling. Rehearsing out loud builds familiarity so the talk feels automatic under pressure. The better you know your opening and your transitions, the less there is to worry about on the day.','Much speaking anxiety comes from fear of forgetting or fumbling. Rehearsing out loud builds familiarity so the talk feels automatic under pressure. The better you know your opening and your transitions, the less there is to worry about on the day.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-nerves-i-1','speaking','speaking:nerves','speaking-nerves-i-1','intermediate','mcq','You feel a surge of adrenaline before speaking. Which mindset reframe is most useful?','You feel a surge of adrenaline before speaking. Which mindset reframe is most useful?',ARRAY['Interpret the arousal as excitement and energy that will help your performance','Tell yourself the feeling means you are about to fail','Try to suppress all emotion and feel nothing','Assume the audience can see exactly how scared you are']::text[],ARRAY['Interpret the arousal as excitement and energy that will help your performance','Tell yourself the feeling means you are about to fail','Try to suppress all emotion and feel nothing','Assume the audience can see exactly how scared you are']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Reframing arousal as excitement keeps the energy without the dread, and it is easier than forcing yourself to feel calm.','Reframing arousal as excitement keeps the energy without the dread, and it is easier than forcing yourself to feel calm.','Anxiety and excitement produce nearly identical bodily signals, so the body is already primed; the label you give it shapes the experience. Telling yourself ''I am excited'' channels that energy into engaged delivery. This reframe is more achievable than trying to extinguish the adrenaline entirely.','Anxiety and excitement produce nearly identical bodily signals, so the body is already primed; the label you give it shapes the experience. Telling yourself ''I am excited'' channels that energy into engaged delivery. This reframe is more achievable than trying to extinguish the adrenaline entirely.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-nerves-i-2','speaking','speaking:nerves','speaking-nerves-i-2','intermediate','mcq','You lose your place mid-talk and your mind goes blank. What is the best in-the-moment recovery?','You lose your place mid-talk and your mind goes blank. What is the best in-the-moment recovery?',ARRAY['Pause, take a breath, glance at your notes or last slide, and resume','Apologize repeatedly and announce that you have frozen','Speed up and improvise unrelated content to fill the silence','Walk off and end the talk early']::text[],ARRAY['Pause, take a breath, glance at your notes or last slide, and resume','Apologize repeatedly and announce that you have frozen','Speed up and improvise unrelated content to fill the silence','Walk off and end the talk early']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A calm pause and a quick glance at your notes lets you find your place without drawing attention to the lapse.','A calm pause and a quick glance at your notes lets you find your place without drawing attention to the lapse.','Brief silences feel much longer to the speaker than to the audience, so a short pause goes mostly unnoticed. Taking a breath and checking your notes or current slide reorients you quickly. Drawing attention to the slip with apologies usually makes it more memorable than the slip itself.','Brief silences feel much longer to the speaker than to the audience, so a short pause goes mostly unnoticed. Taking a breath and checking your notes or current slide reorients you quickly. Drawing attention to the slip with apologies usually makes it more memorable than the slip itself.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-nerves-a-1','speaking','speaking:nerves','speaking-nerves-a-1','advanced','mcq','You want a long-term strategy to build genuine confidence rather than just managing symptoms on the day. Which is most effective?','You want a long-term strategy to build genuine confidence rather than just managing symptoms on the day. Which is most effective?',ARRAY['Seek frequent low-stakes speaking opportunities to build experience through gradual exposure','Avoid all speaking until you feel completely fearless','Rely on a single high-pressure event to overcome the fear at once','Read books about speaking but never actually speak']::text[],ARRAY['Seek frequent low-stakes speaking opportunities to build experience through gradual exposure','Avoid all speaking until you feel completely fearless','Rely on a single high-pressure event to overcome the fear at once','Read books about speaking but never actually speak']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Gradual, repeated exposure desensitizes the fear and builds real competence and confidence over time.','Gradual, repeated exposure desensitizes the fear and builds real competence and confidence over time.','Confidence is built through repeated successful experience, not avoidance. Seeking frequent low-stakes chances to speak lets you accumulate evidence that you can handle it. This gradual exposure steadily lowers anxiety while sharpening skill, which a single dramatic attempt cannot reliably do.','Confidence is built through repeated successful experience, not avoidance. Seeking frequent low-stakes chances to speak lets you accumulate evidence that you can handle it. This gradual exposure steadily lowers anxiety while sharpening skill, which a single dramatic attempt cannot reliably do.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-nerves-a-2','speaking','speaking:nerves','speaking-nerves-a-2','advanced','truefalse','Visualizing yourself delivering the talk successfully can reduce anxiety and improve actual performance.','Visualizing yourself delivering the talk successfully can reduce anxiety and improve actual performance.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Mental rehearsal primes confidence and familiarity, much like physical rehearsal does.','Mental rehearsal primes confidence and familiarity, much like physical rehearsal does.','Visualization is a technique used by athletes and performers to prepare for high-pressure moments. Vividly imagining a smooth, successful delivery builds a sense of familiarity and lowers anticipatory anxiety. It complements physical rehearsal by training the mind to expect success rather than disaster.','Visualization is a technique used by athletes and performers to prepare for high-pressure moments. Vividly imagining a smooth, successful delivery builds a sense of familiarity and lowers anticipatory anxiety. It complements physical rehearsal by training the mind to expect success rather than disaster.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-audience-b-1','speaking','speaking:audience','speaking-audience-b-1','beginner','mcq','You are preparing a talk for a non-technical audience on a technical subject. What should guide your choices most?','You are preparing a talk for a non-technical audience on a technical subject. What should guide your choices most?',ARRAY['Tailoring vocabulary, examples, and depth to what this audience already knows and cares about','Using as much specialist jargon as possible to sound credible','Delivering the exact same talk you would give to experts','Ignoring the audience and focusing only on covering all the content']::text[],ARRAY['Tailoring vocabulary, examples, and depth to what this audience already knows and cares about','Using as much specialist jargon as possible to sound credible','Delivering the exact same talk you would give to experts','Ignoring the audience and focusing only on covering all the content']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Adapting language and examples to the audience''s knowledge ensures they actually understand and stay engaged.','Adapting language and examples to the audience''s knowledge ensures they actually understand and stay engaged.','Audience awareness means starting from what listeners know and value rather than from everything you know. Choosing accessible language and relevant examples bridges the gap to a non-expert audience. A talk that ignores who is listening will lose people no matter how accurate it is.','Audience awareness means starting from what listeners know and value rather than from everything you know. Choosing accessible language and relevant examples bridges the gap to a non-expert audience. A talk that ignores who is listening will lose people no matter how accurate it is.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-audience-b-2','speaking','speaking:audience','speaking-audience-b-2','beginner','truefalse','If you do not know the answer to an audience question, it is better to admit it and offer to follow up than to bluff.','If you do not know the answer to an audience question, it is better to admit it and offer to follow up than to bluff.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Honesty preserves credibility, while a bluff risks being exposed and undermining trust.','Honesty preserves credibility, while a bluff risks being exposed and undermining trust.','Audiences respect speakers who acknowledge the limits of their knowledge. Saying you will find out and follow up is credible and professional. Bluffing an answer risks being wrong in front of everyone, which damages trust far more than a candid ''I don''t know''.','Audiences respect speakers who acknowledge the limits of their knowledge. Saying you will find out and follow up is credible and professional. Bluffing an answer risks being wrong in front of everyone, which damages trust far more than a candid ''I don''t know''.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-audience-i-1','speaking','speaking:audience','speaking-audience-i-1','intermediate','mcq','During Q&A you get a rambling, multi-part question. What is the best way to handle it?','During Q&A you get a rambling, multi-part question. What is the best way to handle it?',ARRAY['Briefly restate the core question you will answer, then respond to that','Try to answer every tangent in the exact order given','Ignore the question entirely and move on','Interrupt the questioner before they finish']::text[],ARRAY['Briefly restate the core question you will answer, then respond to that','Try to answer every tangent in the exact order given','Ignore the question entirely and move on','Interrupt the questioner before they finish']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Restating the core question focuses the exchange, confirms understanding, and lets the whole room follow your answer.','Restating the core question focuses the exchange, confirms understanding, and lets the whole room follow your answer.','Long questions often contain one main point buried in detail. Paraphrasing it back confirms you understood and makes the question audible to everyone. It also lets you frame a focused answer instead of getting lost in every tangent.','Long questions often contain one main point buried in detail. Paraphrasing it back confirms you understood and makes the question audible to everyone. It also lets you frame a focused answer instead of getting lost in every tangent.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-audience-i-2','speaking','speaking:audience','speaking-audience-i-2','intermediate','mcq','A questioner pushes you off-topic toward an issue you would rather not dwell on. Which technique keeps control respectfully?','A questioner pushes you off-topic toward an issue you would rather not dwell on. Which technique keeps control respectfully?',ARRAY['Bridge: briefly acknowledge the point, then steer back to your key message','Argue with the questioner until they concede','Pretend you did not hear and stay silent','Abandon your message and follow wherever the question leads']::text[],ARRAY['Bridge: briefly acknowledge the point, then steer back to your key message','Argue with the questioner until they concede','Pretend you did not hear and stay silent','Abandon your message and follow wherever the question leads']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Bridging acknowledges the question while transitioning back to the message you came to deliver.','Bridging acknowledges the question while transitioning back to the message you came to deliver.','Bridging is a technique for acknowledging a question and then linking back to your main points. A short phrase like ''that''s worth noting, and what really matters here is...'' redirects without dismissing the questioner. It keeps you on message while still treating the audience with respect.','Bridging is a technique for acknowledging a question and then linking back to your main points. A short phrase like ''that''s worth noting, and what really matters here is...'' redirects without dismissing the questioner. It keeps you on message while still treating the audience with respect.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-audience-a-1','speaking','speaking:audience','speaking-audience-a-1','advanced','mcq','A hostile audience member challenges your credibility aggressively during Q&A. What is the most effective response?','A hostile audience member challenges your credibility aggressively during Q&A. What is the most effective response?',ARRAY['Stay calm, acknowledge the concern, respond to the substance, and avoid mirroring the hostility','Match their aggression to show you will not be intimidated','Dismiss them and refuse to engage at all','Become defensive and over-explain at length']::text[],ARRAY['Stay calm, acknowledge the concern, respond to the substance, and avoid mirroring the hostility','Match their aggression to show you will not be intimidated','Dismiss them and refuse to engage at all','Become defensive and over-explain at length']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A calm, substantive response defuses hostility and preserves your authority in front of the rest of the room.','A calm, substantive response defuses hostility and preserves your authority in front of the rest of the room.','Hostile questions are partly performances for the audience, so your composure matters as much as your content. Staying calm and engaging the substance signals confidence and fairness. Mirroring the aggression escalates the conflict and can turn the rest of the room against you.','Hostile questions are partly performances for the audience, so your composure matters as much as your content. Staying calm and engaging the substance signals confidence and fairness. Mirroring the aggression escalates the conflict and can turn the rest of the room against you.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-speaking-audience-a-2','speaking','speaking:audience','speaking-audience-a-2','advanced','truefalse','Reading the room and adjusting your pace or content when the audience looks confused or disengaged is a hallmark of a skilled speaker.','Reading the room and adjusting your pace or content when the audience looks confused or disengaged is a hallmark of a skilled speaker.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Responsive speakers monitor audience cues and adapt in real time to keep the room with them.','Responsive speakers monitor audience cues and adapt in real time to keep the room with them.','Audience feedback is constant and nonverbal: puzzled faces, lost attention, or nods of agreement. Skilled speakers watch for these cues and adjust by slowing down, adding an example, or moving on. This responsiveness keeps the talk a two-way connection rather than a rigid recitation.','Audience feedback is constant and nonverbal: puzzled faces, lost attention, or nods of agreement. Skilled speakers watch for these cues and adjust by slowing down, adding an example, or moving on. This responsiveness keeps the talk a two-way connection rather than a rigid recitation.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-ml-b-1','ai','ai:ml','ai-ml-b-1','beginner','mcq','In machine learning, what distinguishes supervised learning from unsupervised learning?','In machine learning, what distinguishes supervised learning from unsupervised learning?',ARRAY['Supervised learning trains on labeled examples, while unsupervised learning finds structure in unlabeled data','Supervised learning requires a human to watch the model run at all times','Unsupervised learning always produces more accurate predictions than supervised learning','Supervised learning can only be used for images, unsupervised only for text']::text[],ARRAY['Supervised learning trains on labeled examples, while unsupervised learning finds structure in unlabeled data','Supervised learning requires a human to watch the model run at all times','Unsupervised learning always produces more accurate predictions than supervised learning','Supervised learning can only be used for images, unsupervised only for text']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Supervised learning uses input-output pairs with known labels, whereas unsupervised learning discovers patterns such as clusters in data that has no labels.','Supervised learning uses input-output pairs with known labels, whereas unsupervised learning discovers patterns such as clusters in data that has no labels.','Supervised learning learns a mapping from inputs to known target labels, as in classifying emails as spam or not. Unsupervised learning works on data without labels and instead uncovers hidden structure, such as grouping similar customers together. The key difference is whether the correct answers are provided during training.','Supervised learning learns a mapping from inputs to known target labels, as in classifying emails as spam or not. Unsupervised learning works on data without labels and instead uncovers hidden structure, such as grouping similar customers together. The key difference is whether the correct answers are provided during training.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-ml-b-2','ai','ai:ml','ai-ml-b-2','beginner','truefalse','True or false: A classification task predicts a discrete category label, while a regression task predicts a continuous numeric value.','True or false: A classification task predicts a discrete category label, while a regression task predicts a continuous numeric value.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Classification outputs categories such as cat or dog, whereas regression outputs continuous numbers such as a predicted price.','Classification outputs categories such as cat or dog, whereas regression outputs continuous numbers such as a predicted price.','Classification and regression are the two main types of supervised learning problems. Classification assigns inputs to one of a fixed set of classes, like spam versus not spam. Regression predicts a real-valued quantity, such as tomorrow''s temperature or a house price.','Classification and regression are the two main types of supervised learning problems. Classification assigns inputs to one of a fixed set of classes, like spam versus not spam. Regression predicts a real-valued quantity, such as tomorrow''s temperature or a house price.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-ml-i-1','ai','ai:ml','ai-ml-i-1','intermediate','mcq','A model achieves 99% accuracy on training data but only 70% on new test data. What is the most likely problem?','A model achieves 99% accuracy on training data but only 70% on new test data. What is the most likely problem?',ARRAY['Overfitting: the model memorized training noise and fails to generalize','Underfitting: the model is too simple to capture the data','The test set is guaranteed to be corrupted','The learning rate must be set to exactly zero']::text[],ARRAY['Overfitting: the model memorized training noise and fails to generalize','Underfitting: the model is too simple to capture the data','The test set is guaranteed to be corrupted','The learning rate must be set to exactly zero']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A large gap between high training accuracy and lower test accuracy is the classic signature of overfitting.','A large gap between high training accuracy and lower test accuracy is the classic signature of overfitting.','Overfitting happens when a model fits the training data so closely that it captures noise and idiosyncrasies rather than the underlying pattern. Such a model performs well on data it has seen but poorly on new data. Techniques like regularization, more data, and simpler models help improve generalization.','Overfitting happens when a model fits the training data so closely that it captures noise and idiosyncrasies rather than the underlying pattern. Such a model performs well on data it has seen but poorly on new data. Techniques like regularization, more data, and simpler models help improve generalization.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-ml-i-2','ai','ai:ml','ai-ml-i-2','intermediate','mcq','Why is data typically split into separate training and test sets before evaluating a model?','Why is data typically split into separate training and test sets before evaluating a model?',ARRAY['To estimate how well the model generalizes to unseen data rather than data it memorized','To make training run faster by using fewer examples overall','Because models can only read data that has been split into two files','To guarantee the model will reach 100% accuracy on the training set']::text[],ARRAY['To estimate how well the model generalizes to unseen data rather than data it memorized','To make training run faster by using fewer examples overall','Because models can only read data that has been split into two files','To guarantee the model will reach 100% accuracy on the training set']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Holding out a test set gives an honest estimate of performance on data the model never saw during training.','Holding out a test set gives an honest estimate of performance on data the model never saw during training.','If a model is evaluated on the same data it trained on, the score is overly optimistic because the model may have memorized those examples. A held-out test set simulates new, unseen data and provides a fairer measure of generalization. A separate validation set is often used as well to tune hyperparameters without touching the test set.','If a model is evaluated on the same data it trained on, the score is overly optimistic because the model may have memorized those examples. A held-out test set simulates new, unseen data and provides a fairer measure of generalization. A separate validation set is often used as well to tune hyperparameters without touching the test set.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-ml-a-1','ai','ai:ml','ai-ml-a-1','advanced','mcq','In the context of the bias-variance tradeoff, what characterizes a model with high variance?','In the context of the bias-variance tradeoff, what characterizes a model with high variance?',ARRAY['It is very sensitive to the specific training data and tends to overfit','It is too rigid and underfits regardless of the data','It always has lower test error than any low-variance model','It ignores the training data entirely and predicts constants']::text[],ARRAY['It is very sensitive to the specific training data and tends to overfit','It is too rigid and underfits regardless of the data','It always has lower test error than any low-variance model','It ignores the training data entirely and predicts constants']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'High variance means the model changes a lot with different training samples, capturing noise and overfitting.','High variance means the model changes a lot with different training samples, capturing noise and overfitting.','The bias-variance tradeoff describes two sources of error. High bias means the model is too simple and systematically misses the pattern (underfitting). High variance means the model is too flexible and reacts strongly to fluctuations in the training data (overfitting). Good generalization requires balancing the two.','The bias-variance tradeoff describes two sources of error. High bias means the model is too simple and systematically misses the pattern (underfitting). High variance means the model is too flexible and reacts strongly to fluctuations in the training data (overfitting). Good generalization requires balancing the two.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-ml-a-2','ai','ai:ml','ai-ml-a-2','advanced','mcq','When using k-fold cross-validation, what is the primary benefit over a single train-test split?','When using k-fold cross-validation, what is the primary benefit over a single train-test split?',ARRAY['It uses every data point for both training and validation across folds, giving a more reliable performance estimate','It eliminates the need for any test data at all','It always increases the model''s training accuracy to 100%','It removes the need to choose any hyperparameters']::text[],ARRAY['It uses every data point for both training and validation across folds, giving a more reliable performance estimate','It eliminates the need for any test data at all','It always increases the model''s training accuracy to 100%','It removes the need to choose any hyperparameters']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Cross-validation rotates the validation fold so the estimate is averaged over multiple splits, reducing dependence on one lucky or unlucky split.','Cross-validation rotates the validation fold so the estimate is averaged over multiple splits, reducing dependence on one lucky or unlucky split.','In k-fold cross-validation the data is partitioned into k folds; the model is trained k times, each time holding out a different fold for validation. Averaging the results gives a more stable estimate of performance than a single split, especially with limited data. It is particularly useful for comparing models and tuning hyperparameters.','In k-fold cross-validation the data is partitioned into k folds; the model is trained k times, each time holding out a different fold for validation. Averaging the results gives a more stable estimate of performance than a single split, especially with limited data. It is particularly useful for comparing models and tuning hyperparameters.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-neural-b-1','ai','ai:neural','ai-neural-b-1','beginner','mcq','What is the role of an activation function in a neural network?','What is the role of an activation function in a neural network?',ARRAY['It introduces non-linearity so the network can model complex relationships','It stores the training data inside each neuron','It guarantees the network never makes mistakes','It converts the network into a single linear equation']::text[],ARRAY['It introduces non-linearity so the network can model complex relationships','It stores the training data inside each neuron','It guarantees the network never makes mistakes','It converts the network into a single linear equation']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Non-linear activation functions let stacked layers represent complex, non-linear functions instead of collapsing into one linear transformation.','Non-linear activation functions let stacked layers represent complex, non-linear functions instead of collapsing into one linear transformation.','Each neuron computes a weighted sum of its inputs and then applies an activation function. Without a non-linear activation, stacking many layers would still only produce a linear function. Non-linear activations such as ReLU or sigmoid give networks the power to approximate complicated patterns.','Each neuron computes a weighted sum of its inputs and then applies an activation function. Without a non-linear activation, stacking many layers would still only produce a linear function. Non-linear activations such as ReLU or sigmoid give networks the power to approximate complicated patterns.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-neural-b-2','ai','ai:neural','ai-neural-b-2','beginner','truefalse','True or false: A neuron in a neural network computes a weighted sum of its inputs and then applies an activation function to that sum.','True or false: A neuron in a neural network computes a weighted sum of its inputs and then applies an activation function to that sum.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Each neuron multiplies inputs by weights, adds a bias, and passes the result through an activation function.','Each neuron multiplies inputs by weights, adds a bias, and passes the result through an activation function.','An artificial neuron takes several inputs, multiplies each by a learned weight, and adds them together along with a bias term. The resulting value is fed through an activation function to produce the neuron''s output. Connecting many such neurons in layers forms a neural network.','An artificial neuron takes several inputs, multiplies each by a learned weight, and adds them together along with a bias term. The resulting value is fed through an activation function to produce the neuron''s output. Connecting many such neurons in layers forms a neural network.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-neural-i-1','ai','ai:neural','ai-neural-i-1','intermediate','mcq','What does the backpropagation algorithm compute during neural network training?','What does the backpropagation algorithm compute during neural network training?',ARRAY['The gradient of the loss with respect to each weight, used to update the weights','The final accuracy of the model on the test set','A random reshuffling of the training examples','The number of neurons that should be added to each layer']::text[],ARRAY['The gradient of the loss with respect to each weight, used to update the weights','The final accuracy of the model on the test set','A random reshuffling of the training examples','The number of neurons that should be added to each layer']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Backpropagation applies the chain rule to efficiently compute how the loss changes with each weight, enabling gradient-based updates.','Backpropagation applies the chain rule to efficiently compute how the loss changes with each weight, enabling gradient-based updates.','Backpropagation propagates the error from the output layer back through the network using the chain rule of calculus. This yields the gradient of the loss with respect to every weight. An optimizer like gradient descent then nudges each weight in the direction that reduces the loss.','Backpropagation propagates the error from the output layer back through the network using the chain rule of calculus. This yields the gradient of the loss with respect to every weight. An optimizer like gradient descent then nudges each weight in the direction that reduces the loss.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-neural-i-2','ai','ai:neural','ai-neural-i-2','intermediate','mcq','In gradient descent, what is the purpose of the learning rate?','In gradient descent, what is the purpose of the learning rate?',ARRAY['It controls the step size taken when updating weights along the gradient','It sets the number of layers in the network','It determines how many output classes the model has','It measures the accuracy of the model directly']::text[],ARRAY['It controls the step size taken when updating weights along the gradient','It sets the number of layers in the network','It determines how many output classes the model has','It measures the accuracy of the model directly']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The learning rate scales how far weights move on each update; too large can overshoot, too small can be slow.','The learning rate scales how far weights move on each update; too large can overshoot, too small can be slow.','Gradient descent updates weights by moving them opposite to the gradient of the loss. The learning rate is a hyperparameter that multiplies the gradient to decide the size of each step. A rate that is too high can cause the loss to diverge, while one that is too low makes training painfully slow.','Gradient descent updates weights by moving them opposite to the gradient of the loss. The learning rate is a hyperparameter that multiplies the gradient to decide the size of each step. A rate that is too high can cause the loss to diverge, while one that is too low makes training painfully slow.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-neural-a-1','ai','ai:neural','ai-neural-a-1','advanced','mcq','Why is the ReLU activation function often preferred over sigmoid in deep networks?','Why is the ReLU activation function often preferred over sigmoid in deep networks?',ARRAY['ReLU does not saturate for positive inputs, helping mitigate the vanishing gradient problem','ReLU always outputs values between 0 and 1 like a probability','ReLU has no derivative anywhere, which speeds up training','ReLU guarantees the network cannot overfit']::text[],ARRAY['ReLU does not saturate for positive inputs, helping mitigate the vanishing gradient problem','ReLU always outputs values between 0 and 1 like a probability','ReLU has no derivative anywhere, which speeds up training','ReLU guarantees the network cannot overfit']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Sigmoid gradients shrink toward zero for large-magnitude inputs, whereas ReLU keeps a constant gradient of 1 for positive inputs, easing gradient flow in deep nets.','Sigmoid gradients shrink toward zero for large-magnitude inputs, whereas ReLU keeps a constant gradient of 1 for positive inputs, easing gradient flow in deep nets.','The vanishing gradient problem occurs when gradients become extremely small as they propagate back through many layers, stalling learning. Sigmoid and tanh saturate at their extremes, producing tiny gradients. ReLU keeps a gradient of 1 for positive inputs, allowing gradients to flow more effectively through deep networks.','The vanishing gradient problem occurs when gradients become extremely small as they propagate back through many layers, stalling learning. Sigmoid and tanh saturate at their extremes, producing tiny gradients. ReLU keeps a gradient of 1 for positive inputs, allowing gradients to flow more effectively through deep networks.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-neural-a-2','ai','ai:neural','ai-neural-a-2','advanced','mcq','What problem does dropout primarily address during neural network training?','What problem does dropout primarily address during neural network training?',ARRAY['Overfitting, by randomly deactivating neurons so the network cannot rely on any single one','Slow data loading from disk during each epoch','The need to compute gradients at all','Choosing the optimal number of output classes']::text[],ARRAY['Overfitting, by randomly deactivating neurons so the network cannot rely on any single one','Slow data loading from disk during each epoch','The need to compute gradients at all','Choosing the optimal number of output classes']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Dropout randomly zeros out neurons during training, forcing redundancy and acting as a regularizer that reduces overfitting.','Dropout randomly zeros out neurons during training, forcing redundancy and acting as a regularizer that reduces overfitting.','Dropout is a regularization technique where, during each training step, a random subset of neurons is temporarily turned off. This prevents the network from becoming overly dependent on specific neurons and encourages more robust, distributed representations. At inference time all neurons are used, with activations scaled appropriately.','Dropout is a regularization technique where, during each training step, a random subset of neurons is temporarily turned off. This prevents the network from becoming overly dependent on specific neurons and encourages more robust, distributed representations. At inference time all neurons are used, with activations scaled appropriately.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-llms-b-1','ai','ai:llms','ai-llms-b-1','beginner','mcq','In a large language model, what is a token?','In a large language model, what is a token?',ARRAY['A chunk of text, often a word or sub-word piece, that the model processes as a unit','A password that unlocks the model','A single pixel in an input image','The name of the optimizer used during training']::text[],ARRAY['A chunk of text, often a word or sub-word piece, that the model processes as a unit','A password that unlocks the model','A single pixel in an input image','The name of the optimizer used during training']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Text is broken into tokens (words or sub-word fragments) which are the basic units the model reads and predicts.','Text is broken into tokens (words or sub-word fragments) which are the basic units the model reads and predicts.','Language models do not read raw characters directly; instead text is split into tokens by a tokenizer. A token may be a whole word, a sub-word fragment, or punctuation. The model processes sequences of tokens and predicts the next token, and usage and context limits are measured in tokens.','Language models do not read raw characters directly; instead text is split into tokens by a tokenizer. A token may be a whole word, a sub-word fragment, or punctuation. The model processes sequences of tokens and predicts the next token, and usage and context limits are measured in tokens.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-llms-b-2','ai','ai:llms','ai-llms-b-2','beginner','truefalse','True or false: An embedding represents a token or piece of text as a vector of numbers that captures aspects of its meaning.','True or false: An embedding represents a token or piece of text as a vector of numbers that captures aspects of its meaning.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Embeddings map tokens or text into numeric vectors where similar meanings tend to be located close together.','Embeddings map tokens or text into numeric vectors where similar meanings tend to be located close together.','An embedding is a dense vector of real numbers that represents a token, word, or chunk of text. These vectors are learned so that items with similar meaning or usage end up near each other in the vector space. Embeddings let models and search systems reason about semantic similarity numerically.','An embedding is a dense vector of real numbers that represents a token, word, or chunk of text. These vectors are learned so that items with similar meaning or usage end up near each other in the vector space. Embeddings let models and search systems reason about semantic similarity numerically.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-llms-i-1','ai','ai:llms','ai-llms-i-1','intermediate','mcq','What core mechanism in the transformer architecture lets a model weigh the relevance of different tokens to each other?','What core mechanism in the transformer architecture lets a model weigh the relevance of different tokens to each other?',ARRAY['Self-attention','Max pooling','A single fixed convolution filter','Manual keyword matching']::text[],ARRAY['Self-attention','Max pooling','A single fixed convolution filter','Manual keyword matching']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Self-attention lets each token attend to and incorporate information from other tokens based on learned relevance scores.','Self-attention lets each token attend to and incorporate information from other tokens based on learned relevance scores.','Transformers, introduced in 2017, rely on the self-attention mechanism to relate tokens within a sequence. For each token, attention computes weighted combinations of other tokens based on their relevance. This lets the model capture long-range dependencies and context far more flexibly than older recurrent approaches.','Transformers, introduced in 2017, rely on the self-attention mechanism to relate tokens within a sequence. For each token, attention computes weighted combinations of other tokens based on their relevance. This lets the model capture long-range dependencies and context far more flexibly than older recurrent approaches.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-llms-i-2','ai','ai:llms','ai-llms-i-2','intermediate','mcq','What does a language model''s context window refer to?','What does a language model''s context window refer to?',ARRAY['The maximum amount of text, measured in tokens, the model can consider at once','The screen resolution required to display the model''s output','The number of parameters in the model','The time of day the model is allowed to run']::text[],ARRAY['The maximum amount of text, measured in tokens, the model can consider at once','The screen resolution required to display the model''s output','The number of parameters in the model','The time of day the model is allowed to run']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The context window is the token limit for the combined prompt and generated output that the model can attend to in a single pass.','The context window is the token limit for the combined prompt and generated output that the model can attend to in a single pass.','The context window is the maximum number of tokens a model can process together, including the prompt and its response. Text beyond this limit must be truncated, summarized, or otherwise handled. Larger context windows let models work with longer documents and conversations, but they increase computational cost.','The context window is the maximum number of tokens a model can process together, including the prompt and its response. Text beyond this limit must be truncated, summarized, or otherwise handled. Larger context windows let models work with longer documents and conversations, but they increase computational cost.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-llms-a-1','ai','ai:llms','ai-llms-a-1','advanced','mcq','What is the main purpose of Retrieval-Augmented Generation (RAG)?','What is the main purpose of Retrieval-Augmented Generation (RAG)?',ARRAY['To fetch relevant external documents at query time and feed them into the prompt so answers are grounded in that information','To permanently retrain the model''s weights on each new question','To compress the model so it runs on smaller hardware','To remove the need for any prompt at all']::text[],ARRAY['To fetch relevant external documents at query time and feed them into the prompt so answers are grounded in that information','To permanently retrain the model''s weights on each new question','To compress the model so it runs on smaller hardware','To remove the need for any prompt at all']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'RAG retrieves relevant text from an external knowledge source and supplies it as context, grounding responses without retraining the model.','RAG retrieves relevant text from an external knowledge source and supplies it as context, grounding responses without retraining the model.','Retrieval-Augmented Generation combines a retrieval step with generation. When a query arrives, relevant documents are fetched from a knowledge base, often using embedding-based similarity search, and inserted into the model''s context. This grounds answers in up-to-date or proprietary information and can reduce hallucination without modifying the model''s weights.','Retrieval-Augmented Generation combines a retrieval step with generation. When a query arrives, relevant documents are fetched from a knowledge base, often using embedding-based similarity search, and inserted into the model''s context. This grounds answers in up-to-date or proprietary information and can reduce hallucination without modifying the model''s weights.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-llms-a-2','ai','ai:llms','ai-llms-a-2','advanced','mcq','In the context of large language models, what does the term hallucination describe?','In the context of large language models, what does the term hallucination describe?',ARRAY['When the model produces fluent, confident output that is factually incorrect or unsupported','When the model refuses to answer any question','When the model runs out of memory and crashes','When the model only outputs text it has copied verbatim from training data']::text[],ARRAY['When the model produces fluent, confident output that is factually incorrect or unsupported','When the model refuses to answer any question','When the model runs out of memory and crashes','When the model only outputs text it has copied verbatim from training data']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A hallucination is plausible-sounding but false or fabricated content generated by the model.','A hallucination is plausible-sounding but false or fabricated content generated by the model.','Language models generate text by predicting likely token sequences, not by looking up verified facts. As a result they can produce confident statements that are wrong or invented, known as hallucinations. Grounding techniques like RAG, citation, and careful evaluation help detect and reduce them.','Language models generate text by predicting likely token sequences, not by looking up verified facts. As a result they can produce confident statements that are wrong or invented, known as hallucinations. Grounding techniques like RAG, citation, and careful evaluation help detect and reduce them.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-prompting-b-1','ai','ai:prompting','ai-prompting-b-1','beginner','mcq','What does few-shot prompting mean?','What does few-shot prompting mean?',ARRAY['Including a few example input-output pairs in the prompt to guide the model''s response','Running the model only a few times per day','Training the model from scratch on a few images','Limiting the model to answers of a few words']::text[],ARRAY['Including a few example input-output pairs in the prompt to guide the model''s response','Running the model only a few times per day','Training the model from scratch on a few images','Limiting the model to answers of a few words']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Few-shot prompting provides several worked examples in the prompt so the model can infer the desired pattern.','Few-shot prompting provides several worked examples in the prompt so the model can infer the desired pattern.','Few-shot prompting gives the model a handful of examples demonstrating the task within the prompt itself. The model uses these examples to infer the expected format and behavior, without any change to its weights. Zero-shot prompting, by contrast, provides instructions but no examples.','Few-shot prompting gives the model a handful of examples demonstrating the task within the prompt itself. The model uses these examples to infer the expected format and behavior, without any change to its weights. Zero-shot prompting, by contrast, provides instructions but no examples.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-prompting-b-2','ai','ai:prompting','ai-prompting-b-2','beginner','mcq','When sampling from a language model, what does a higher temperature setting generally do?','When sampling from a language model, what does a higher temperature setting generally do?',ARRAY['Makes the output more random and varied','Makes the output strictly shorter','Forces the model to always pick the single most likely token','Disables the model''s ability to generate text']::text[],ARRAY['Makes the output more random and varied','Makes the output strictly shorter','Forces the model to always pick the single most likely token','Disables the model''s ability to generate text']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Higher temperature flattens the probability distribution over tokens, increasing randomness and diversity in the output.','Higher temperature flattens the probability distribution over tokens, increasing randomness and diversity in the output.','Temperature is a sampling parameter that scales the model''s token probabilities before selection. Low temperature makes the model favor the most probable tokens, producing focused and deterministic text. High temperature spreads probability more evenly, yielding more diverse and creative but less predictable output.','Temperature is a sampling parameter that scales the model''s token probabilities before selection. Low temperature makes the model favor the most probable tokens, producing focused and deterministic text. High temperature spreads probability more evenly, yielding more diverse and creative but less predictable output.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-prompting-i-1','ai','ai:prompting','ai-prompting-i-1','intermediate','mcq','What is the main idea behind chain-of-thought prompting?','What is the main idea behind chain-of-thought prompting?',ARRAY['Encouraging the model to generate intermediate reasoning steps before giving a final answer','Chaining several different models together in a pipeline','Forcing the model to answer in a single word','Hiding all instructions from the model']::text[],ARRAY['Encouraging the model to generate intermediate reasoning steps before giving a final answer','Chaining several different models together in a pipeline','Forcing the model to answer in a single word','Hiding all instructions from the model']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Chain-of-thought prompting asks the model to reason step by step, which often improves accuracy on multi-step problems.','Chain-of-thought prompting asks the model to reason step by step, which often improves accuracy on multi-step problems.','Chain-of-thought prompting instructs or shows the model to work through a problem in explicit intermediate steps rather than jumping straight to an answer. This tends to improve performance on tasks that require arithmetic, logic, or multi-step reasoning. The reasoning trace also makes the model''s process more transparent and easier to check.','Chain-of-thought prompting instructs or shows the model to work through a problem in explicit intermediate steps rather than jumping straight to an answer. This tends to improve performance on tasks that require arithmetic, logic, or multi-step reasoning. The reasoning trace also makes the model''s process more transparent and easier to check.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-prompting-i-2','ai','ai:prompting','ai-prompting-i-2','intermediate','truefalse','True or false: Setting temperature to 0 makes a language model''s sampling effectively deterministic, usually selecting the most probable next token each time.','True or false: Setting temperature to 0 makes a language model''s sampling effectively deterministic, usually selecting the most probable next token each time.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'At temperature 0 the model greedily picks the highest-probability token, so for a given prompt the output is essentially deterministic.','At temperature 0 the model greedily picks the highest-probability token, so for a given prompt the output is essentially deterministic.','Temperature controls randomness in token sampling. As temperature approaches 0, the distribution collapses onto the single most likely token, a strategy known as greedy decoding. This produces consistent, repeatable output, which is useful when you want reliable answers rather than creative variety.','Temperature controls randomness in token sampling. As temperature approaches 0, the distribution collapses onto the single most likely token, a strategy known as greedy decoding. This produces consistent, repeatable output, which is useful when you want reliable answers rather than creative variety.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-prompting-a-1','ai','ai:prompting','ai-prompting-a-1','advanced','mcq','When evaluating an LLM on an open-ended generation task, why is exact-match accuracy against a single reference often a poor metric?','When evaluating an LLM on an open-ended generation task, why is exact-match accuracy against a single reference often a poor metric?',ARRAY['Many different responses can be equally correct, so a single reference unfairly penalizes valid variations','Exact-match always overestimates model quality','Open-ended tasks have no correct answers at all','Exact-match can only be used for images']::text[],ARRAY['Many different responses can be equally correct, so a single reference unfairly penalizes valid variations','Exact-match always overestimates model quality','Open-ended tasks have no correct answers at all','Exact-match can only be used for images']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Open-ended tasks admit many valid wordings, so requiring an exact string match misses correct answers phrased differently.','Open-ended tasks admit many valid wordings, so requiring an exact string match misses correct answers phrased differently.','For open-ended generation there is rarely one right answer; correct responses can vary in wording, structure, and detail. Exact-match scoring against a single reference therefore underestimates quality. Better approaches include human evaluation, rubric-based grading, semantic similarity, or using a strong model as a judge.','For open-ended generation there is rarely one right answer; correct responses can vary in wording, structure, and detail. Exact-match scoring against a single reference therefore underestimates quality. Better approaches include human evaluation, rubric-based grading, semantic similarity, or using a strong model as a judge.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-ai-prompting-a-2','ai','ai:prompting','ai-prompting-a-2','advanced','mcq','What is a key risk when using an LLM as an automated judge to evaluate other models'' outputs?','What is a key risk when using an LLM as an automated judge to evaluate other models'' outputs?',ARRAY['The judge can carry its own biases, such as favoring longer or more confident answers regardless of correctness','The judge is mathematically guaranteed to be perfectly accurate','The judge cannot read text at all','Using an LLM judge removes all need for any reference answers, with no downsides']::text[],ARRAY['The judge can carry its own biases, such as favoring longer or more confident answers regardless of correctness','The judge is mathematically guaranteed to be perfectly accurate','The judge cannot read text at all','Using an LLM judge removes all need for any reference answers, with no downsides']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'LLM judges exhibit systematic biases, such as preferring verbose or self-assured responses, which can distort evaluation results.','LLM judges exhibit systematic biases, such as preferring verbose or self-assured responses, which can distort evaluation results.','Using an LLM as a judge scales evaluation but introduces reliability concerns. Such judges can show position bias, verbosity bias, and a tendency to prefer outputs that resemble their own style. Calibrating with human-labeled examples, randomizing answer order, and using clear rubrics help mitigate these biases.','Using an LLM as a judge scales evaluation but introduces reliability concerns. Such judges can show position bias, verbosity bias, and a tendency to prefer outputs that resemble their own style. Calibrating with human-labeled examples, randomizing answer order, and using clear rubrics help mitigate these biases.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-mechanics-b-1','engineering','engineering:mechanics','engineering-mechanics-b-1','beginner','mcq','A constant net force of 10 N acts on a 2 kg cart on a frictionless surface. Using Newton''s second law (F = m * a), what is the cart''s acceleration?','A constant net force of 10 N acts on a 2 kg cart on a frictionless surface. Using Newton''s second law (F = m * a), what is the cart''s acceleration?',ARRAY['5 m/s^2','20 m/s^2','0.2 m/s^2','12 m/s^2']::text[],ARRAY['5 m/s^2','20 m/s^2','0.2 m/s^2','12 m/s^2']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Acceleration is force divided by mass, so a = 10 N / 2 kg = 5 m/s^2.','Acceleration is force divided by mass, so a = 10 N / 2 kg = 5 m/s^2.','Newton''s second law states that net force equals mass times acceleration (F = m * a). Solving for acceleration gives a = F / m. The unit newton is defined so that 1 N accelerates 1 kg at 1 m/s^2.','Newton''s second law states that net force equals mass times acceleration (F = m * a). Solving for acceleration gives a = F / m. The unit newton is defined so that 1 N accelerates 1 kg at 1 m/s^2.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-mechanics-b-2','engineering','engineering:mechanics','engineering-mechanics-b-2','beginner','truefalse','True or false: The weight of an object equals its mass multiplied by the local gravitational acceleration g.','True or false: The weight of an object equals its mass multiplied by the local gravitational acceleration g.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Weight is the gravitational force on a mass, given by W = m * g.','Weight is the gravitational force on a mass, given by W = m * g.','Mass is the amount of matter in an object and is the same everywhere. Weight is a force caused by gravity acting on that mass, calculated as W = m * g. On Earth g is about 9.81 m/s^2, so a 1 kg mass weighs about 9.81 N.','Mass is the amount of matter in an object and is the same everywhere. Weight is a force caused by gravity acting on that mass, calculated as W = m * g. On Earth g is about 9.81 m/s^2, so a 1 kg mass weighs about 9.81 N.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-mechanics-i-1','engineering','engineering:mechanics','engineering-mechanics-i-1','intermediate','mcq','A force of 20 N is applied at the end of a wrench 0.25 m long, perpendicular to the handle. What torque does it produce about the bolt?','A force of 20 N is applied at the end of a wrench 0.25 m long, perpendicular to the handle. What torque does it produce about the bolt?',ARRAY['5 N*m','80 N*m','0.0125 N*m','20.25 N*m']::text[],ARRAY['5 N*m','80 N*m','0.0125 N*m','20.25 N*m']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Torque equals force times perpendicular lever arm, so 20 N * 0.25 m = 5 N*m.','Torque equals force times perpendicular lever arm, so 20 N * 0.25 m = 5 N*m.','Torque is the rotational effect of a force, calculated as the force multiplied by the perpendicular distance from the pivot (tau = F * r). It is measured in newton-meters. A longer lever arm produces more torque for the same applied force.','Torque is the rotational effect of a force, calculated as the force multiplied by the perpendicular distance from the pivot (tau = F * r). It is measured in newton-meters. A longer lever arm produces more torque for the same applied force.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-mechanics-i-2','engineering','engineering:mechanics','engineering-mechanics-i-2','intermediate','mcq','A 4 kg object moves at 3 m/s. What is its kinetic energy, using KE = (1/2) * m * v^2?','A 4 kg object moves at 3 m/s. What is its kinetic energy, using KE = (1/2) * m * v^2?',ARRAY['18 J','36 J','12 J','6 J']::text[],ARRAY['18 J','36 J','12 J','6 J']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'KE = 0.5 * 4 kg * (3 m/s)^2 = 0.5 * 4 * 9 = 18 J.','KE = 0.5 * 4 kg * (3 m/s)^2 = 0.5 * 4 * 9 = 18 J.','Kinetic energy is the energy of motion, given by KE = (1/2) * m * v^2. Because velocity is squared, doubling the speed quadruples the kinetic energy. Energy is measured in joules (J), where 1 J = 1 kg*m^2/s^2.','Kinetic energy is the energy of motion, given by KE = (1/2) * m * v^2. Because velocity is squared, doubling the speed quadruples the kinetic energy. Energy is measured in joules (J), where 1 J = 1 kg*m^2/s^2.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-mechanics-a-1','engineering','engineering:mechanics','engineering-mechanics-a-1','advanced','mcq','A steel rod can withstand a maximum (ultimate) tensile stress of 400 MPa. If the working stress in service is 100 MPa, what is the factor of safety?','A steel rod can withstand a maximum (ultimate) tensile stress of 400 MPa. If the working stress in service is 100 MPa, what is the factor of safety?',ARRAY['4','0.25','300','40']::text[],ARRAY['4','0.25','300','40']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Factor of safety is ultimate stress divided by working stress, so 400 MPa / 100 MPa = 4.','Factor of safety is ultimate stress divided by working stress, so 400 MPa / 100 MPa = 4.','The factor of safety is the ratio of a material''s failure strength to the actual stress it experiences in use. A value greater than 1 means the design has margin before failure. Engineers pick larger factors when loads are uncertain or failure would be dangerous.','The factor of safety is the ratio of a material''s failure strength to the actual stress it experiences in use. A value greater than 1 means the design has margin before failure. Engineers pick larger factors when loads are uncertain or failure would be dangerous.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-mechanics-a-2','engineering','engineering:mechanics','engineering-mechanics-a-2','advanced','mcq','A simply supported beam carries a single central point load of 600 N over a span of 4 m. What is the maximum bending moment at the center, given M = (P * L) / 4?','A simply supported beam carries a single central point load of 600 N over a span of 4 m. What is the maximum bending moment at the center, given M = (P * L) / 4?',ARRAY['600 N*m','2400 N*m','150 N*m','300 N*m']::text[],ARRAY['600 N*m','2400 N*m','150 N*m','300 N*m']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'M = (P * L) / 4 = (600 N * 4 m) / 4 = 600 N*m.','M = (P * L) / 4 = (600 N * 4 m) / 4 = 600 N*m.','For a simply supported beam with a central point load, the maximum bending moment occurs at midspan and equals (P * L) / 4. Bending moment measures the internal turning effect that tends to bend the beam. It is largest where the beam is most likely to fail in bending.','For a simply supported beam with a central point load, the maximum bending moment occurs at midspan and equals (P * L) / 4. Bending moment measures the internal turning effect that tends to bend the beam. It is largest where the beam is most likely to fail in bending.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-circuits-b-1','engineering','engineering:circuits','engineering-circuits-b-1','beginner','mcq','A 12 V battery is connected across a 4 ohm resistor. Using Ohm''s law (V = I * R), what current flows through the resistor?','A 12 V battery is connected across a 4 ohm resistor. Using Ohm''s law (V = I * R), what current flows through the resistor?',ARRAY['3 A','48 A','0.33 A','16 A']::text[],ARRAY['3 A','48 A','0.33 A','16 A']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Current is voltage divided by resistance, so I = 12 V / 4 ohm = 3 A.','Current is voltage divided by resistance, so I = 12 V / 4 ohm = 3 A.','Ohm''s law relates voltage, current, and resistance as V = I * R. Rearranged, current equals voltage divided by resistance (I = V / R). For a fixed voltage, a smaller resistance allows a larger current to flow.','Ohm''s law relates voltage, current, and resistance as V = I * R. Rearranged, current equals voltage divided by resistance (I = V / R). For a fixed voltage, a smaller resistance allows a larger current to flow.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-circuits-b-2','engineering','engineering:circuits','engineering-circuits-b-2','beginner','truefalse','True or false: In a series circuit, the same current flows through every component.','True or false: In a series circuit, the same current flows through every component.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A series circuit provides a single path, so the current is identical through all components.','A series circuit provides a single path, so the current is identical through all components.','In a series circuit, components are connected end to end forming one path for current. Because there is only one path, the current is the same everywhere in the loop. The supply voltage divides across the components in proportion to their resistances.','In a series circuit, components are connected end to end forming one path for current. Because there is only one path, the current is the same everywhere in the loop. The supply voltage divides across the components in proportion to their resistances.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-circuits-i-1','engineering','engineering:circuits','engineering-circuits-i-1','intermediate','mcq','Two resistors of 6 ohm and 3 ohm are connected in parallel. What is their equivalent resistance?','Two resistors of 6 ohm and 3 ohm are connected in parallel. What is their equivalent resistance?',ARRAY['2 ohm','9 ohm','4.5 ohm','18 ohm']::text[],ARRAY['2 ohm','9 ohm','4.5 ohm','18 ohm']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'For parallel resistors, 1/R = 1/6 + 1/3 = 1/2, so R = 2 ohm.','For parallel resistors, 1/R = 1/6 + 1/3 = 1/2, so R = 2 ohm.','Resistors in parallel share the same voltage but split the current. The equivalent resistance is found from 1/R = 1/R1 + 1/R2. The result is always smaller than the smallest individual resistor because there are more paths for current.','Resistors in parallel share the same voltage but split the current. The equivalent resistance is found from 1/R = 1/R1 + 1/R2. The result is always smaller than the smallest individual resistor because there are more paths for current.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-circuits-i-2','engineering','engineering:circuits','engineering-circuits-i-2','intermediate','mcq','A device draws 2 A at 120 V. What is its power consumption, using P = V * I?','A device draws 2 A at 120 V. What is its power consumption, using P = V * I?',ARRAY['240 W','60 W','122 W','480 W']::text[],ARRAY['240 W','60 W','122 W','480 W']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Power equals voltage times current, so P = 120 V * 2 A = 240 W.','Power equals voltage times current, so P = 120 V * 2 A = 240 W.','Electrical power is the rate of energy use, given by P = V * I. It is measured in watts, where 1 W = 1 J/s. Combined with Ohm''s law, power can also be written as P = I^2 * R or P = V^2 / R.','Electrical power is the rate of energy use, given by P = V * I. It is measured in watts, where 1 W = 1 J/s. Combined with Ohm''s law, power can also be written as P = I^2 * R or P = V^2 / R.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-circuits-a-1','engineering','engineering:circuits','engineering-circuits-a-1','advanced','mcq','An RC circuit has R = 10 kohm and C = 100 uF. What is its time constant (tau = R * C)?','An RC circuit has R = 10 kohm and C = 100 uF. What is its time constant (tau = R * C)?',ARRAY['1 s','0.1 s','10 s','0.001 s']::text[],ARRAY['1 s','0.1 s','10 s','0.001 s']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'tau = R * C = 10000 ohm * 0.0001 F = 1 s.','tau = R * C = 10000 ohm * 0.0001 F = 1 s.','The time constant of an RC circuit is tau = R * C and sets how fast a capacitor charges or discharges. After one time constant the capacitor reaches about 63 percent of its final voltage. Using SI units (ohms and farads) gives the result directly in seconds.','The time constant of an RC circuit is tau = R * C and sets how fast a capacitor charges or discharges. After one time constant the capacitor reaches about 63 percent of its final voltage. Using SI units (ohms and farads) gives the result directly in seconds.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-circuits-a-2','engineering','engineering:circuits','engineering-circuits-a-2','advanced','mcq','A resistor carries 0.5 A and has 8 ohm of resistance. Using P = I^2 * R, how much power does it dissipate as heat?','A resistor carries 0.5 A and has 8 ohm of resistance. Using P = I^2 * R, how much power does it dissipate as heat?',ARRAY['2 W','4 W','16 W','0.25 W']::text[],ARRAY['2 W','4 W','16 W','0.25 W']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'P = I^2 * R = (0.5)^2 * 8 = 0.25 * 8 = 2 W.','P = I^2 * R = (0.5)^2 * 8 = 0.25 * 8 = 2 W.','Power dissipated in a resistor can be computed as P = I^2 * R, which follows from combining P = V * I with Ohm''s law V = I * R. This heat-generating loss is called Joule heating. Because current is squared, doubling the current quadruples the dissipated power.','Power dissipated in a resistor can be computed as P = I^2 * R, which follows from combining P = V * I with Ohm''s law V = I * R. This heat-generating loss is called Joule heating. Because current is squared, doubling the current quadruples the dissipated power.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-algorithms-b-1','engineering','engineering:algorithms','engineering-algorithms-b-1','beginner','mcq','What is the time complexity of a linear search through an unsorted array of n elements in the worst case?','What is the time complexity of a linear search through an unsorted array of n elements in the worst case?',ARRAY['O(n)','O(1)','O(log n)','O(n^2)']::text[],ARRAY['O(n)','O(1)','O(log n)','O(n^2)']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'In the worst case linear search checks every one of the n elements, giving O(n).','In the worst case linear search checks every one of the n elements, giving O(n).','Linear search scans elements one by one until it finds the target or reaches the end. In the worst case the target is last or absent, requiring all n comparisons. This makes its time complexity O(n), meaning runtime grows in proportion to the input size.','Linear search scans elements one by one until it finds the target or reaches the end. In the worst case the target is last or absent, requiring all n comparisons. This makes its time complexity O(n), meaning runtime grows in proportion to the input size.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-algorithms-b-2','engineering','engineering:algorithms','engineering-algorithms-b-2','beginner','truefalse','True or false: Binary search requires the input array to be sorted beforehand.','True or false: Binary search requires the input array to be sorted beforehand.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Binary search relies on order to discard half the search space each step, so the data must be sorted.','Binary search relies on order to discard half the search space each step, so the data must be sorted.','Binary search repeatedly compares the target to the middle element and eliminates half of the remaining elements. This halving only works if the array is sorted so that the discarded half cannot contain the target. Its time complexity is O(log n).','Binary search repeatedly compares the target to the middle element and eliminates half of the remaining elements. This halving only works if the array is sorted so that the discarded half cannot contain the target. Its time complexity is O(log n).',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-algorithms-i-1','engineering','engineering:algorithms','engineering-algorithms-i-1','intermediate','mcq','What is the average and worst-case time complexity of binary search on a sorted array of n elements?','What is the average and worst-case time complexity of binary search on a sorted array of n elements?',ARRAY['O(log n)','O(n)','O(1)','O(n log n)']::text[],ARRAY['O(log n)','O(n)','O(1)','O(n log n)']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Binary search halves the search space each step, so it takes about log base 2 of n steps, giving O(log n).','Binary search halves the search space each step, so it takes about log base 2 of n steps, giving O(log n).','Each comparison in binary search removes half of the remaining candidates. The number of halvings needed to reduce n elements to one is log base 2 of n. Therefore both the average and worst-case time complexity is O(log n).','Each comparison in binary search removes half of the remaining candidates. The number of halvings needed to reduce n elements to one is log base 2 of n. Therefore both the average and worst-case time complexity is O(log n).',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-algorithms-i-2','engineering','engineering:algorithms','engineering-algorithms-i-2','intermediate','mcq','Which data structure follows Last-In First-Out (LIFO) order, where the most recently added item is removed first?','Which data structure follows Last-In First-Out (LIFO) order, where the most recently added item is removed first?',ARRAY['Stack','Queue','Linked list','Hash table']::text[],ARRAY['Stack','Queue','Linked list','Hash table']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A stack adds and removes elements at the same end, so the last item pushed is the first popped.','A stack adds and removes elements at the same end, so the last item pushed is the first popped.','A stack is a linear data structure with push and pop operations at one end, giving Last-In First-Out behavior. A queue, by contrast, is First-In First-Out. Stacks are used for function call management, undo features, and expression evaluation.','A stack is a linear data structure with push and pop operations at one end, giving Last-In First-Out behavior. A queue, by contrast, is First-In First-Out. Stacks are used for function call management, undo features, and expression evaluation.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-algorithms-a-1','engineering','engineering:algorithms','engineering-algorithms-a-1','advanced','mcq','What is the average-case time complexity of the merge sort algorithm when sorting n elements?','What is the average-case time complexity of the merge sort algorithm when sorting n elements?',ARRAY['O(n log n)','O(n^2)','O(n)','O(log n)']::text[],ARRAY['O(n log n)','O(n^2)','O(n)','O(log n)']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Merge sort splits into log n levels and does O(n) work merging at each level, giving O(n log n).','Merge sort splits into log n levels and does O(n) work merging at each level, giving O(n log n).','Merge sort recursively divides the array in half until single elements remain, then merges sorted halves. There are about log base 2 of n levels of division, and each level requires O(n) work to merge. The total is O(n log n) in the best, average, and worst cases.','Merge sort recursively divides the array in half until single elements remain, then merges sorted halves. There are about log base 2 of n levels of division, and each level requires O(n) work to merge. The total is O(n log n) in the best, average, and worst cases.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-algorithms-a-2','engineering','engineering:algorithms','engineering-algorithms-a-2','advanced','mcq','A nested loop iterates j from 0 to n for each i from 0 to n, doing constant work inside. What is the overall time complexity?','A nested loop iterates j from 0 to n for each i from 0 to n, doing constant work inside. What is the overall time complexity?',ARRAY['O(n^2)','O(n)','O(2n)','O(n log n)']::text[],ARRAY['O(n^2)','O(n)','O(2n)','O(n log n)']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The inner loop runs n times for each of the n outer iterations, giving n * n = O(n^2) operations.','The inner loop runs n times for each of the n outer iterations, giving n * n = O(n^2) operations.','When one loop is nested inside another and each runs n times, the total iterations multiply to n^2. Constant work inside the loops does not change the order of growth. This quadratic behavior is written O(n^2) and scales poorly for large n.','When one loop is nested inside another and each runs n times, the total iterations multiply to n^2. Constant work inside the loops does not change the order of growth. This quadratic behavior is written O(n^2) and scales poorly for large n.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-reliability-b-1','engineering','engineering:reliability','engineering-reliability-b-1','beginner','mcq','How many milliamperes (mA) are in 2.5 amperes (A)?','How many milliamperes (mA) are in 2.5 amperes (A)?',ARRAY['2500 mA','250 mA','25 mA','0.0025 mA']::text[],ARRAY['2500 mA','250 mA','25 mA','0.0025 mA']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The prefix milli means one-thousandth, so 2.5 A * 1000 = 2500 mA.','The prefix milli means one-thousandth, so 2.5 A * 1000 = 2500 mA.','SI prefixes scale base units by powers of ten. The prefix milli (m) means one-thousandth, so 1 A equals 1000 mA. To convert from amperes to milliamperes you multiply by 1000.','SI prefixes scale base units by powers of ten. The prefix milli (m) means one-thousandth, so 1 A equals 1000 mA. To convert from amperes to milliamperes you multiply by 1000.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-reliability-b-2','engineering','engineering:reliability','engineering-reliability-b-2','beginner','truefalse','True or false: One kilometer equals 1000 meters.','True or false: One kilometer equals 1000 meters.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The prefix kilo means one thousand, so 1 km = 1000 m.','The prefix kilo means one thousand, so 1 km = 1000 m.','In the SI system the prefix kilo (k) multiplies a base unit by one thousand. Thus one kilometer is 1000 meters and one kilogram is 1000 grams. Recognizing prefixes lets you convert between unit scales reliably.','In the SI system the prefix kilo (k) multiplies a base unit by one thousand. Thus one kilometer is 1000 meters and one kilogram is 1000 grams. Recognizing prefixes lets you convert between unit scales reliably.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-reliability-i-1','engineering','engineering:reliability','engineering-reliability-i-1','intermediate','mcq','A system is available 23.76 hours out of every 24-hour day. What is its availability expressed as a percentage?','A system is available 23.76 hours out of every 24-hour day. What is its availability expressed as a percentage?',ARRAY['99%','90%','97.6%','95%']::text[],ARRAY['99%','90%','97.6%','95%']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Availability = 23.76 / 24 = 0.99, which is 99%.','Availability = 23.76 / 24 = 0.99, which is 99%.','Availability is the fraction of time a system is operational, computed as uptime divided by total time. Multiplying by 100 expresses it as a percentage. A value of 99% corresponds to roughly 0.24 hours (about 14 minutes) of downtime per day.','Availability is the fraction of time a system is operational, computed as uptime divided by total time. Multiplying by 100 expresses it as a percentage. A value of 99% corresponds to roughly 0.24 hours (about 14 minutes) of downtime per day.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-reliability-i-2','engineering','engineering:reliability','engineering-reliability-i-2','intermediate','mcq','Convert a pressure of 2 kilopascals (kPa) to pascals (Pa).','Convert a pressure of 2 kilopascals (kPa) to pascals (Pa).',ARRAY['2000 Pa','200 Pa','20000 Pa','0.002 Pa']::text[],ARRAY['2000 Pa','200 Pa','20000 Pa','0.002 Pa']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The prefix kilo means one thousand, so 2 kPa = 2 * 1000 = 2000 Pa.','The prefix kilo means one thousand, so 2 kPa = 2 * 1000 = 2000 Pa.','The pascal (Pa) is the SI unit of pressure, equal to one newton per square meter. The prefix kilo multiplies by one thousand, so 1 kPa = 1000 Pa. Converting 2 kPa therefore gives 2000 Pa.','The pascal (Pa) is the SI unit of pressure, equal to one newton per square meter. The prefix kilo multiplies by one thousand, so 1 kPa = 1000 Pa. Converting 2 kPa therefore gives 2000 Pa.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-reliability-a-1','engineering','engineering:reliability','engineering-reliability-a-1','advanced','mcq','A service must meet 99.9% availability over a 30-day month (720 hours). What is the maximum allowed downtime?','A service must meet 99.9% availability over a 30-day month (720 hours). What is the maximum allowed downtime?',ARRAY['About 43.2 minutes','About 7.2 hours','About 4.32 minutes','About 72 minutes']::text[],ARRAY['About 43.2 minutes','About 7.2 hours','About 4.32 minutes','About 72 minutes']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Allowed downtime = 0.001 * 720 h = 0.72 h = 43.2 minutes.','Allowed downtime = 0.001 * 720 h = 0.72 h = 43.2 minutes.','Allowed downtime equals the unavailability fraction times the total period. For 99.9% availability the unavailability is 0.1%, or 0.001. Over 720 hours this is 0.72 hours, which is about 43.2 minutes per month.','Allowed downtime equals the unavailability fraction times the total period. For 99.9% availability the unavailability is 0.1%, or 0.001. Over 720 hours this is 0.72 hours, which is about 43.2 minutes per month.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-engineering-reliability-a-2','engineering','engineering:reliability','engineering-reliability-a-2','advanced','mcq','A component has a mean time between failures (MTBF) of 1000 hours and a mean time to repair (MTTR) of 10 hours. What is its steady-state availability, using MTBF / (MTBF + MTTR)?','A component has a mean time between failures (MTBF) of 1000 hours and a mean time to repair (MTTR) of 10 hours. What is its steady-state availability, using MTBF / (MTBF + MTTR)?',ARRAY['About 99.0%','About 90.0%','About 99.9%','About 50.0%']::text[],ARRAY['About 99.0%','About 90.0%','About 99.9%','About 50.0%']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Availability = 1000 / (1000 + 10) = 1000 / 1010 = 0.990, or about 99.0%.','Availability = 1000 / (1000 + 10) = 1000 / 1010 = 0.990, or about 99.0%.','Steady-state availability is the fraction of time a repairable system is working, given by MTBF / (MTBF + MTTR). MTBF measures how long the system runs between failures and MTTR measures how long repairs take. Increasing MTBF or reducing MTTR raises availability.','Steady-state availability is the fraction of time a repairable system is working, given by MTBF / (MTBF + MTTR). MTBF measures how long the system runs between failures and MTTR measures how long repairs take. Increasing MTBF or reducing MTTR raises availability.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-openings-b-1','chess','chess:openings','chess-openings-b-1','beginner','mcq','Which of these is a core opening principle in chess?','Which of these is a core opening principle in chess?',ARRAY['Control the center','Move the same piece many times','Bring the queen out immediately','Push every pawn forward']::text[],ARRAY['Control the center','Move the same piece many times','Bring the queen out immediately','Push every pawn forward']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Controlling the central squares gives your pieces maximum mobility and influence.','Controlling the central squares gives your pieces maximum mobility and influence.','The center (the e4, d4, e5, and d5 squares) is the most valuable real estate on the board. Pieces placed near or controlling the center reach more squares and react faster to threats. Classic openings begin with central pawn moves like 1.e4 or 1.d4 for this reason.','The center (the e4, d4, e5, and d5 squares) is the most valuable real estate on the board. Pieces placed near or controlling the center reach more squares and react faster to threats. Classic openings begin with central pawn moves like 1.e4 or 1.d4 for this reason.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-openings-b-2','chess','chess:openings','chess-openings-b-2','beginner','truefalse','True or False: It is generally good to castle early in the opening to keep your king safe.','True or False: It is generally good to castle early in the opening to keep your king safe.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Castling tucks the king behind a pawn shield and connects the rooks, so doing it early is sound.','Castling tucks the king behind a pawn shield and connects the rooks, so doing it early is sound.','Castling moves the king to a safer corner and brings a rook toward the center in a single move. Leaving the king in the center too long exposes it to attacks down open files. Most opening plans aim to castle within the first ten moves.','Castling moves the king to a safer corner and brings a rook toward the center in a single move. Leaving the king in the center too long exposes it to attacks down open files. Most opening plans aim to castle within the first ten moves.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-openings-i-1','chess','chess:openings','chess-openings-i-1','intermediate','mcq','After 1.e4 e5 2.Nf3 Nc6 3.Bb5, which famous opening has been reached?','After 1.e4 e5 2.Nf3 Nc6 3.Bb5, which famous opening has been reached?',ARRAY['Ruy Lopez (Spanish Opening)','Italian Game','Sicilian Defense','French Defense']::text[],ARRAY['Ruy Lopez (Spanish Opening)','Italian Game','Sicilian Defense','French Defense']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The bishop move to b5, pressuring the knight defending e5, defines the Ruy Lopez.','The bishop move to b5, pressuring the knight defending e5, defines the Ruy Lopez.','The Ruy Lopez, or Spanish Opening, arises after 1.e4 e5 2.Nf3 Nc6 3.Bb5. White pins pressure on the c6 knight that supports the e5 pawn, creating long-term positional tension. It is one of the oldest and most deeply studied openings in chess.','The Ruy Lopez, or Spanish Opening, arises after 1.e4 e5 2.Nf3 Nc6 3.Bb5. White pins pressure on the c6 knight that supports the e5 pawn, creating long-term positional tension. It is one of the oldest and most deeply studied openings in chess.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-openings-i-2','chess','chess:openings','chess-openings-i-2','intermediate','mcq','What is the main idea behind a gambit such as the King''s Gambit (1.e4 e5 2.f4)?','What is the main idea behind a gambit such as the King''s Gambit (1.e4 e5 2.f4)?',ARRAY['Sacrifice a pawn to gain rapid development and open lines','Trade queens as quickly as possible','Avoid moving any pawns in the center','Force an immediate draw']::text[],ARRAY['Sacrifice a pawn to gain rapid development and open lines','Trade queens as quickly as possible','Avoid moving any pawns in the center','Force an immediate draw']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A gambit gives up material, usually a pawn, in exchange for faster development and attacking chances.','A gambit gives up material, usually a pawn, in exchange for faster development and attacking chances.','A gambit offers material, most often a pawn, to accelerate piece development and open lines toward the enemy king. The attacking side hopes the initiative outweighs the lost pawn. If the defender survives the early pressure, the extra material can decide the endgame.','A gambit offers material, most often a pawn, to accelerate piece development and open lines toward the enemy king. The attacking side hopes the initiative outweighs the lost pawn. If the defender survives the early pressure, the extra material can decide the endgame.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-openings-a-1','chess','chess:openings','chess-openings-a-1','advanced','mcq','In the Sicilian Defense, why does Black often accept a slightly cramped position with moves like ...d6 and ...e6?','In the Sicilian Defense, why does Black often accept a slightly cramped position with moves like ...d6 and ...e6?',ARRAY['To create an asymmetrical structure with strong counterattacking chances on the queenside','To force an immediate queen trade','To avoid ever moving a knight','To guarantee a symmetrical pawn structure']::text[],ARRAY['To create an asymmetrical structure with strong counterattacking chances on the queenside','To force an immediate queen trade','To avoid ever moving a knight','To guarantee a symmetrical pawn structure']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'By answering 1.e4 with 1...c5, Black creates an unbalanced position aiming for active counterplay, often on the queenside.','By answering 1.e4 with 1...c5, Black creates an unbalanced position aiming for active counterplay, often on the queenside.','The Sicilian (1.e4 c5) trades central symmetry for a half-open c-file and queenside counterplay. Black often accepts a spatial disadvantage in return for dynamic, unbalanced positions where both sides play for a win. It is the most popular response to 1.e4 at the top level for exactly this fighting character.','The Sicilian (1.e4 c5) trades central symmetry for a half-open c-file and queenside counterplay. Black often accepts a spatial disadvantage in return for dynamic, unbalanced positions where both sides play for a win. It is the most popular response to 1.e4 at the top level for exactly this fighting character.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-openings-a-2','chess','chess:openings','chess-openings-a-2','advanced','truefalse','True or False: In closed openings, it is acceptable to delay development to first establish a strong pawn structure, whereas in open positions rapid development is more urgent.','True or False: In closed openings, it is acceptable to delay development to first establish a strong pawn structure, whereas in open positions rapid development is more urgent.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Open positions punish slow development sharply, while closed structures grant more time for maneuvering.','Open positions punish slow development sharply, while closed structures grant more time for maneuvering.','When the center is open, lines are available for pieces to strike quickly, so a lead in development can be decisive and even justify sacrifices. In closed positions the locked pawns blunt direct attacks, allowing slower maneuvering plans. Reading whether a position is open or closed guides how urgently you must develop.','When the center is open, lines are available for pieces to strike quickly, so a lead in development can be decisive and even justify sacrifices. In closed positions the locked pawns blunt direct attacks, allowing slower maneuvering plans. Reading whether a position is open or closed guides how urgently you must develop.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-tactics-b-1','chess','chess:tactics','chess-tactics-b-1','beginner','mcq','A single knight attacks both the enemy king and queen at the same time. What is this tactic called?','A single knight attacks both the enemy king and queen at the same time. What is this tactic called?',ARRAY['Fork','Pin','Skewer','Zugzwang']::text[],ARRAY['Fork','Pin','Skewer','Zugzwang']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'One piece attacking two or more enemy pieces simultaneously is a fork.','One piece attacking two or more enemy pieces simultaneously is a fork.','A fork is a double attack from a single piece, hitting two or more targets at once. Knights are especially good at forking because their unusual movement is hard to block. When the king is one of the forked pieces, the opponent must move it and you win the other target.','A fork is a double attack from a single piece, hitting two or more targets at once. Knights are especially good at forking because their unusual movement is hard to block. When the king is one of the forked pieces, the opponent must move it and you win the other target.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-tactics-b-2','chess','chess:tactics','chess-tactics-b-2','beginner','mcq','A bishop attacks a knight, and behind that knight on the same line sits the king, so the knight cannot move. What is this called?','A bishop attacks a knight, and behind that knight on the same line sits the king, so the knight cannot move. What is this called?',ARRAY['A pin','A fork','A discovered check','A stalemate']::text[],ARRAY['A pin','A fork','A discovered check','A stalemate']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A piece pinned against the king is absolutely pinned and may not legally move.','A piece pinned against the king is absolutely pinned and may not legally move.','A pin occurs when a piece cannot move because doing so would expose a more valuable piece behind it. When the piece behind is the king, the pin is absolute and the pinned piece is frozen entirely. Pins restrict the opponent and set up follow-up attacks on the immobilized piece.','A pin occurs when a piece cannot move because doing so would expose a more valuable piece behind it. When the piece behind is the king, the pin is absolute and the pinned piece is frozen entirely. Pins restrict the opponent and set up follow-up attacks on the immobilized piece.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-tactics-i-1','chess','chess:tactics','chess-tactics-i-1','intermediate','mcq','A rook attacks the enemy king, and when the king moves out of check, a more valuable queen standing behind it on the same line is captured. What is this tactic called?','A rook attacks the enemy king, and when the king moves out of check, a more valuable queen standing behind it on the same line is captured. What is this tactic called?',ARRAY['Skewer','Pin','Fork','Interference']::text[],ARRAY['Skewer','Pin','Fork','Interference']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A skewer is like a reversed pin: the more valuable piece is in front and forced to move, exposing the piece behind.','A skewer is like a reversed pin: the more valuable piece is in front and forced to move, exposing the piece behind.','A skewer attacks a valuable piece that is forced to move, exposing a less valuable piece behind it on the same line. It is the inverse of a pin, where the more valuable piece sits behind. Skewers are delivered by line pieces: rooks, bishops, and queens.','A skewer attacks a valuable piece that is forced to move, exposing a less valuable piece behind it on the same line. It is the inverse of a pin, where the more valuable piece sits behind. Skewers are delivered by line pieces: rooks, bishops, and queens.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-tactics-i-2','chess','chess:tactics','chess-tactics-i-2','intermediate','mcq','You move a knight that was blocking your bishop, and the bishop now gives check while the knight also captures a piece. What general tactic is this?','You move a knight that was blocking your bishop, and the bishop now gives check while the knight also captures a piece. What general tactic is this?',ARRAY['Discovered attack','Back-rank mate','Stalemate','Underpromotion']::text[],ARRAY['Discovered attack','Back-rank mate','Stalemate','Underpromotion']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Moving one piece to unveil an attack from another behind it is a discovered attack, and when it gives check it is doubly dangerous.','Moving one piece to unveil an attack from another behind it is a discovered attack, and when it gives check it is doubly dangerous.','A discovered attack happens when moving one piece uncovers an attack from a piece behind it. The moving piece can make its own threat at the same time, creating a double attack. A discovered check is especially powerful because the opponent must address the check, leaving the moving piece free to capture.','A discovered attack happens when moving one piece uncovers an attack from a piece behind it. The moving piece can make its own threat at the same time, creating a double attack. A discovered check is especially powerful because the opponent must address the check, leaving the moving piece free to capture.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-tactics-a-1','chess','chess:tactics','chess-tactics-a-1','advanced','mcq','A sacrifice that removes or diverts the only defender of a key square or piece is best described as which tactical theme?','A sacrifice that removes or diverts the only defender of a key square or piece is best described as which tactical theme?',ARRAY['Deflection / removing the defender','The opposition','Triangulation','Fianchetto']::text[],ARRAY['Deflection / removing the defender','The opposition','Triangulation','Fianchetto']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Deflection forces a defending piece away from its duty, after which the undefended target falls.','Deflection forces a defending piece away from its duty, after which the undefended target falls.','Deflection, also called removing the defender, lures or forces a piece away from a square or piece it is guarding. Once the defender is gone, a follow-up move wins material or delivers mate. Recognizing which enemy piece is overworked is the key to spotting these combinations.','Deflection, also called removing the defender, lures or forces a piece away from a square or piece it is guarding. Once the defender is gone, a follow-up move wins material or delivers mate. Recognizing which enemy piece is overworked is the key to spotting these combinations.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-tactics-a-2','chess','chess:tactics','chess-tactics-a-2','advanced','truefalse','True or False: A back-rank mate exploits a king trapped on its starting rank by its own unmoved pawns, allowing a rook or queen to deliver checkmate along that rank.','True or False: A back-rank mate exploits a king trapped on its starting rank by its own unmoved pawns, allowing a rook or queen to deliver checkmate along that rank.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'When the pawns in front of a castled king have not moved, an invading rook or queen on the back rank can checkmate.','When the pawns in front of a castled king have not moved, an invading rook or queen on the back rank can checkmate.','A back-rank mate occurs when a king is boxed in on its home rank by its own pawns and has no escape squares. A rook or queen delivering check along that rank then gives checkmate. Players often prevent it by making a ''luft'' move, advancing a pawn to give the king an escape square.','A back-rank mate occurs when a king is boxed in on its home rank by its own pawns and has no escape squares. A rook or queen delivering check along that rank then gives checkmate. Players often prevent it by making a ''luft'' move, advancing a pawn to give the king an escape square.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-endgames-b-1','chess','chess:endgames','chess-endgames-b-1','beginner','mcq','Which pieces are sufficient, together with the king, to force checkmate against a lone king?','Which pieces are sufficient, together with the king, to force checkmate against a lone king?',ARRAY['King and queen','King and single knight','King and single bishop','Two knights (no other pieces)']::text[],ARRAY['King and queen','King and single knight','King and single bishop','Two knights (no other pieces)']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A king and queen can force mate against a lone king, while a single minor piece or two knights cannot.','A king and queen can force mate against a lone king, while a single minor piece or two knights cannot.','Basic checkmates are a core endgame skill: king and queen, or king and rook, can force mate against a lone king. A king with only one bishop or one knight has insufficient material to mate. Two knights cannot force mate against a bare king either, making the queen and rook the reliable mating pieces.','Basic checkmates are a core endgame skill: king and queen, or king and rook, can force mate against a lone king. A king with only one bishop or one knight has insufficient material to mate. Two knights cannot force mate against a bare king either, making the queen and rook the reliable mating pieces.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-endgames-b-2','chess','chess:endgames','chess-endgames-b-2','beginner','truefalse','True or False: In the endgame, it becomes important and usually safe to activate your king and use it as a fighting piece.','True or False: In the endgame, it becomes important and usually safe to activate your king and use it as a fighting piece.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'With few pieces left, the king faces little mating danger and becomes a strong attacker and defender.','With few pieces left, the king faces little mating danger and becomes a strong attacker and defender.','In the middlegame the king must hide from attacks, but as pieces are traded off the danger of mate drops sharply. In the endgame the king becomes a powerful piece, roughly as strong as a minor piece, and should march toward the action. Centralizing the king is often the single most important endgame idea.','In the middlegame the king must hide from attacks, but as pieces are traded off the danger of mate drops sharply. In the endgame the king becomes a powerful piece, roughly as strong as a minor piece, and should march toward the action. Centralizing the king is often the single most important endgame idea.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-endgames-i-1','chess','chess:endgames','chess-endgames-i-1','intermediate','mcq','In king and pawn endgames, what does ''the opposition'' refer to?','In king and pawn endgames, what does ''the opposition'' refer to?',ARRAY['Placing your king directly facing the enemy king with one square between them, forcing the other king to give way','Putting both rooks on the same file','Trading queens to simplify','Promoting a pawn to a knight']::text[],ARRAY['Placing your king directly facing the enemy king with one square between them, forcing the other king to give way','Putting both rooks on the same file','Trading queens to simplify','Promoting a pawn to a knight']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Holding the opposition forces the opposing king to step aside, letting your king gain key squares.','Holding the opposition forces the opposing king to step aside, letting your king gain key squares.','The opposition is a king-and-pawn endgame technique where the kings stand on the same line with one square between them, and it is the opponent''s move. The side not having to move holds the opposition and can outflank the enemy king. Winning the opposition often decides whether a pawn can promote.','The opposition is a king-and-pawn endgame technique where the kings stand on the same line with one square between them, and it is the opponent''s move. The side not having to move holds the opposition and can outflank the enemy king. Winning the opposition often decides whether a pawn can promote.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-endgames-i-2','chess','chess:endgames','chess-endgames-i-2','intermediate','mcq','What is the ''Rule of the Square'' used for in pawn endgames?','What is the ''Rule of the Square'' used for in pawn endgames?',ARRAY['Quickly checking whether a king can catch a passed pawn before it promotes','Calculating the value of a bishop','Deciding where to castle','Counting how many pawns are doubled']::text[],ARRAY['Quickly checking whether a king can catch a passed pawn before it promotes','Calculating the value of a bishop','Deciding where to castle','Counting how many pawns are doubled']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The rule of the square lets you see at a glance whether a defending king is close enough to stop a runner.','The rule of the square lets you see at a glance whether a defending king is close enough to stop a runner.','The Rule of the Square is a shortcut for passed-pawn races: imagine a square whose side stretches from the pawn to its promotion rank. If the defending king can step into that square on its move, it can catch the pawn; if not, the pawn promotes. It saves you from counting moves one by one.','The Rule of the Square is a shortcut for passed-pawn races: imagine a square whose side stretches from the pawn to its promotion rank. If the defending king can step into that square on its move, it can catch the pawn; if not, the pawn promotes. It saves you from counting moves one by one.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-endgames-a-1','chess','chess:endgames','chess-endgames-a-1','advanced','mcq','In rook endgames, what does the principle ''rooks belong behind passed pawns'' mean?','In rook endgames, what does the principle ''rooks belong behind passed pawns'' mean?',ARRAY['A rook should be placed behind a passed pawn, whether yours to push it or the enemy''s to restrain it','A rook should always stay on the first rank','Rooks should be traded as soon as possible','Rooks must shield the king at all times']::text[],ARRAY['A rook should be placed behind a passed pawn, whether yours to push it or the enemy''s to restrain it','A rook should always stay on the first rank','Rooks should be traded as soon as possible','Rooks must shield the king at all times']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'A rook behind a passed pawn supports its advance, or behind the enemy''s pawn ties down the defender, gaining activity as the pawn moves.','A rook behind a passed pawn supports its advance, or behind the enemy''s pawn ties down the defender, gaining activity as the pawn moves.','This Tarrasch principle states that rooks are most effective behind passed pawns. Behind your own passer, the rook supports each advance while staying mobile. Behind the enemy''s passer, it restrains the pawn while the defending rook is passively tied to blocking it.','This Tarrasch principle states that rooks are most effective behind passed pawns. Behind your own passer, the rook supports each advance while staying mobile. Behind the enemy''s passer, it restrains the pawn while the defending rook is passively tied to blocking it.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-endgames-a-2','chess','chess:endgames','chess-endgames-a-2','advanced','truefalse','True or False: A rook-and-pawn endgame with a defending rook on the third rank in front of the pawn, known as the Philidor position, is a well-known fortress draw.','True or False: A rook-and-pawn endgame with a defending rook on the third rank in front of the pawn, known as the Philidor position, is a well-known fortress draw.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'The Philidor defense holds the third rank until the pawn advances, then checks the attacking king from behind to force a draw.','The Philidor defense holds the third rank until the pawn advances, then checks the attacking king from behind to force a draw.','The Philidor position is a fundamental drawing technique in rook endgames where the weaker side keeps its rook on the third rank. This prevents the enemy king from advancing in front of the pawn. Once the pawn pushes to the sixth rank, the defending rook swings behind to deliver perpetual checks, securing the draw.','The Philidor position is a fundamental drawing technique in rook endgames where the weaker side keeps its rook on the third rank. This prevents the enemy king from advancing in front of the pawn. Once the pawn pushes to the sixth rank, the defending rook swings behind to deliver perpetual checks, securing the draw.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-strategy-b-1','chess','chess:strategy','chess-strategy-b-1','beginner','mcq','Using the standard relative values, how many points is a rook worth?','Using the standard relative values, how many points is a rook worth?',ARRAY['5','3','9','1']::text[],ARRAY['5','3','9','1']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'In the common point system, a rook is worth about 5 points.','In the common point system, a rook is worth about 5 points.','Relative piece values guide trading decisions: pawn 1, knight and bishop about 3, rook 5, and queen about 9. These numbers are guidelines rather than absolutes, since activity and position matter too. Knowing them helps you judge whether a trade or sacrifice gains or loses material.','Relative piece values guide trading decisions: pawn 1, knight and bishop about 3, rook 5, and queen about 9. These numbers are guidelines rather than absolutes, since activity and position matter too. Knowing them helps you judge whether a trade or sacrifice gains or loses material.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-strategy-b-2','chess','chess:strategy','chess-strategy-b-2','beginner','truefalse','True or False: Doubled pawns (two of your pawns on the same file) are generally considered a structural weakness.','True or False: Doubled pawns (two of your pawns on the same file) are generally considered a structural weakness.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Doubled pawns cannot defend each other and are often harder to advance, making them a typical weakness.','Doubled pawns cannot defend each other and are often harder to advance, making them a typical weakness.','Doubled pawns occur when two pawns of the same color sit on the same file, usually after a capture. They cannot protect one another and the rear pawn is often immobile, so they are generally a weakness. They can occasionally be useful by granting open or half-open files for rooks.','Doubled pawns occur when two pawns of the same color sit on the same file, usually after a capture. They cannot protect one another and the rear pawn is often immobile, so they are generally a weakness. They can occasionally be useful by granting open or half-open files for rooks.',10,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-strategy-i-1','chess','chess:strategy','chess-strategy-i-1','intermediate','mcq','What is an ''outpost'' in chess strategy?','What is an ''outpost'' in chess strategy?',ARRAY['A square, often protected by a pawn and not attackable by enemy pawns, where a knight can sit strongly','A pawn that has reached the last rank','The square the king starts on','Any square on the edge of the board']::text[],ARRAY['A square, often protected by a pawn and not attackable by enemy pawns, where a knight can sit strongly','A pawn that has reached the last rank','The square the king starts on','Any square on the edge of the board']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'An outpost is a secure advanced square, ideal for a knight, that enemy pawns can no longer challenge.','An outpost is a secure advanced square, ideal for a knight, that enemy pawns can no longer challenge.','An outpost is a square in or near the enemy''s half that cannot be attacked by enemy pawns, ideally defended by one of your own pawns. A knight placed on an outpost is extremely powerful because it cannot be easily driven away. Establishing a knight on a central outpost is a classic long-term strategic goal.','An outpost is a square in or near the enemy''s half that cannot be attacked by enemy pawns, ideally defended by one of your own pawns. A knight placed on an outpost is extremely powerful because it cannot be easily driven away. Establishing a knight on a central outpost is a classic long-term strategic goal.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-strategy-i-2','chess','chess:strategy','chess-strategy-i-2','intermediate','mcq','Why is an isolated pawn (a pawn with no friendly pawns on adjacent files) considered both a weakness and a potential asset?','Why is an isolated pawn (a pawn with no friendly pawns on adjacent files) considered both a weakness and a potential asset?',ARRAY['It cannot be defended by pawns and may be a target, but it can grant open files and space for active pieces','It can never be captured','It automatically promotes faster','It makes castling illegal']::text[],ARRAY['It cannot be defended by pawns and may be a target, but it can grant open files and space for active pieces','It can never be captured','It automatically promotes faster','It makes castling illegal']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'An isolated pawn must be defended by pieces and can be a target, yet the open files beside it give pieces extra activity.','An isolated pawn must be defended by pieces and can be a target, yet the open files beside it give pieces extra activity.','An isolated pawn has no neighboring friendly pawns to defend it, so it must be guarded by pieces and can become a long-term target. However, the half-open files on either side give rooks and other pieces active lines, and the pawn can control useful central squares. Whether it helps or hurts depends on how active the pieces around it are.','An isolated pawn has no neighboring friendly pawns to defend it, so it must be guarded by pieces and can become a long-term target. However, the half-open files on either side give rooks and other pieces active lines, and the pawn can control useful central squares. Whether it helps or hurts depends on how active the pieces around it are.',15,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-strategy-a-1','chess','chess:strategy','chess-strategy-a-1','advanced','mcq','What does the principle of ''the bishop pair'' refer to in strategic play?','What does the principle of ''the bishop pair'' refer to in strategic play?',ARRAY['Owning both bishops, which work well together in open positions covering both color complexes','Having two bishops on the same color squares','Trading both bishops immediately','Placing bishops side by side on adjacent files']::text[],ARRAY['Owning both bishops, which work well together in open positions covering both color complexes','Having two bishops on the same color squares','Trading both bishops immediately','Placing bishops side by side on adjacent files']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Two bishops cover squares of both colors and coordinate powerfully, especially when the position opens up.','Two bishops cover squares of both colors and coordinate powerfully, especially when the position opens up.','The bishop pair is the advantage of having both bishops while the opponent does not. Because each bishop covers only one color, owning both lets you control squares of both colors and create threats across the whole board. This advantage grows in open positions with long diagonals and few blocking pawns.','The bishop pair is the advantage of having both bishops while the opponent does not. Because each bishop covers only one color, owning both lets you control squares of both colors and create threats across the whole board. This advantage grows in open positions with long diagonals and few blocking pawns.',25,'approved','curated-bank');
INSERT INTO "BankQuestion" ("id","skillId","subareaKey","concept","difficulty","type","questionEn","questionPl","optionsEn","optionsPl","correctIndex","acceptedAnswers","orderItems","correctOrder","explanationEn","explanationPl","theoryEn","theoryPl","xp","qualityState","model") VALUES ('bankq-chess-strategy-a-2','chess','chess:strategy','chess-strategy-a-2','advanced','truefalse','True or False: A sound strategic plan should be based on the specific features of the position, such as pawn structure, weak squares, and piece activity, rather than on a fixed sequence of memorized moves.','True or False: A sound strategic plan should be based on the specific features of the position, such as pawn structure, weak squares, and piece activity, rather than on a fixed sequence of memorized moves.',ARRAY['True','False']::text[],ARRAY['True','False']::text[],0,ARRAY[]::text[],ARRAY[]::text[],ARRAY[]::int[],'Good plans flow from concrete positional features, not from rote move sequences that ignore the opponent''s play.','Good plans flow from concrete positional features, not from rote move sequences that ignore the opponent''s play.','Strategic planning means choosing goals that fit the position''s pawn structure, weak squares, open files, and piece placement. A plan grounded in these features adapts to what the board actually demands. Blindly following memorized moves without understanding the underlying reasons leads to plans that collapse when the opponent deviates.','Strategic planning means choosing goals that fit the position''s pawn structure, weak squares, open files, and piece placement. A plan grounded in these features adapts to what the board actually demands. Blindly following memorized moves without understanding the underlying reasons leads to plans that collapse when the opponent deviates.',25,'approved','curated-bank');
